//! x86_64 MMU layer (M3): privileged paging-register wrappers + the in-HAL
//! 4 KiB map/remap self-test spliced into the LIVE boot page tables.
//!
//! M0's PVH trampoline (boot.rs) built a three-table boot hierarchy —
//! `__boot_pml4[0] -> __boot_pdpt[0] -> __boot_pd[0..512]`, identity-mapping
//! [0, 1 GiB) with 2 MiB pages — and loaded it into CR3. M3 does NOT replace
//! that hierarchy; it EXTENDS it at runtime through the shared typed table
//! layer ([`crate::mmu::PageTable512`]) plus static 4 KiB frames in `.bss`:
//!
//!  * [`mmu_init`] — set IA32_EFER.NXE (MSR `0xC000_0080`, bit 11) so bit 63
//!    of a paging entry becomes the architectural execute-disable (XD) bit
//!    instead of a reserved bit that would #PF. IA32_PAT (MSR `0x277`) keeps
//!    its power-up default (acceptable for M3; PAT entry 0 = WB).
//!  * [`mmu_selftest`] — walk CR3 -> PML4[0] to the live boot PDPT; splice a
//!    NEW 4 KiB mapping for `TEST_VA = 0x4000_0000` (1 GiB: the first byte
//!    OUTSIDE the boot identity map, so PDPT index 1 is vacant) through two
//!    static tables (PDPT[1] -> TEST_PD, PD[0] -> TEST_PT, PT[0] -> FRAME_A);
//!    prove the mapping by writing a magic THROUGH `TEST_VA` and reading it
//!    back through FRAME_A's identity address; then RETARGET the leaf PTE to
//!    FRAME_B + `invlpg` and prove the remap by reading FRAME_B's magic
//!    through `TEST_VA`. Splicing into the live hierarchy needs no CR3
//!    reload; only the present-leaf change requires `invlpg`.
//!
//! Verified facts (primary sources; every bit value cross-checked against
//! Linux v6.6 headers, which transcribe the same SDM tables):
//!  * Paging-entry format — Intel SDM Vol 3A §4.5, Table 4-15 ff. (PML4E /
//!    PDPTE / PDE / PTE): bit 0 = P (present), bit 1 = R/W, bit 7 = PS (page
//!    size: 1 GiB at PDPTE / 2 MiB at PDE level), bit 63 = XD (execute
//!    disable; only defined when EFER.NXE = 1, reserved otherwise),
//!    physical-address field = bits 51:12. Linux
//!    `arch/x86/include/asm/pgtable_types.h`: `_PAGE_BIT_PRESENT 0`,
//!    `_PAGE_BIT_RW 1`, `_PAGE_BIT_PSE 7`, `_PAGE_BIT_NX 63` ("No execute:
//!    only valid after cpuid check").
//!  * EFER / PAT — SDM Vol 4 Table 2-2: IA32_EFER = MSR `0xC000_0080` with
//!    NXE = bit 11; IA32_PAT = MSR `0x277`. Linux
//!    `arch/x86/include/asm/msr-index.h`: `MSR_EFER 0xc0000080`,
//!    `_EFER_NX 11`, `MSR_IA32_CR_PAT 0x00000277`.
//!  * INVLPG — SDM Vol 2A "INVLPG — Invalidate TLB Entries": invalidates any
//!    TLB entry for the page containing the memory operand. SDM Vol 3A
//!    §4.10.4.2 requires invalidation after modifying a PRESENT entry that
//!    may be cached; §4.10.4.3 permits SKIPPING it for a 0 -> 1 P-flag
//!    transition (the TLB never caches not-present entries).
//!  * CR4.PGE = bit 7 — SDM Vol 3A §2.5 "Control Registers"; Linux
//!    `arch/x86/include/uapi/asm/processor-flags.h`: `X86_CR4_PGE_BIT 7`.
//!    Clearing then re-setting PGE is the architectural "flush ALL TLB
//!    entries, global included" idiom (SDM Vol 3A §4.10.4.1).
//!  * Technique — OSDev wiki "Paging" / "x86-64" (splice-into-live-tables +
//!    invalidate-on-modify; the wiki mirrors the SDM rules above).

use core::arch::asm;
use core::cell::UnsafeCell;
use core::ptr::{read_volatile, write_volatile};

use crate::mmu::PageTable512;

// ---------------------------------------------------------------------------
// Architectural constants (verified — see module header).
// ---------------------------------------------------------------------------

/// IA32_EFER MSR address (SDM Vol 4 Table 2-2; Linux `MSR_EFER`).
const MSR_EFER: u32 = 0xC000_0080;

/// IA32_EFER.NXE — bit 11, "Execute Disable Bit Enable" (Linux `_EFER_NX`).
const EFER_NXE: u64 = 1 << 11;

/// CR4.PGE — bit 7, "Page Global Enable" (Linux `X86_CR4_PGE_BIT`).
const CR4_PGE: u64 = 1 << 7;

/// Paging-entry bit 0: Present (SDM Table 4-15; Linux `_PAGE_BIT_PRESENT`).
const PTE_P: u64 = 1 << 0;

/// Paging-entry bit 1: Read/Write (SDM Table 4-15; Linux `_PAGE_BIT_RW`).
const PTE_RW: u64 = 1 << 1;

/// Physical-address field of any paging entry: bits 51:12 (SDM Table 4-15).
/// Masking with it also strips flag/ignored bits (and XD) when walking.
const PTE_ADDR_MASK: u64 = 0x000F_FFFF_FFFF_F000;

/// The M3 test virtual address: 1 GiB — the first address OUTSIDE the boot
/// identity map (boot maps exactly [0, 1 GiB)), so its translation MUST come
/// from the freshly spliced tables and can never be satisfied by a stale
/// boot-table entry.
const TEST_VA: usize = 0x4000_0000;

/// `TEST_VA`'s PML4 index — VA bits 47:39 = 0 (shared with the boot map).
const PML4_IDX: usize = (TEST_VA >> 39) & 0x1FF;

/// `TEST_VA`'s PDPT index — VA bits 38:30 = 1 (the VACANT second-GiB slot).
const PDPT_IDX: usize = (TEST_VA >> 30) & 0x1FF;

/// `TEST_VA`'s PD index — VA bits 29:21 = 0.
const PD_IDX: usize = (TEST_VA >> 21) & 0x1FF;

/// `TEST_VA`'s PT index — VA bits 20:12 = 0.
const PT_IDX: usize = (TEST_VA >> 12) & 0x1FF;

/// Magic the self-test writes THROUGH `TEST_VA` into frame A (b"M3frameA").
const MAGIC_A: u64 = 0x4D33_6672_616D_6541;

/// Magic pre-seeded into frame B via its identity address and read back
/// THROUGH `TEST_VA` after the remap (b"M3frameB").
const MAGIC_B: u64 = 0x4D33_6672_616D_6542;

// ---------------------------------------------------------------------------
// Static 4 KiB cells (.bss): two new paging-structure tables + two frames.
// ---------------------------------------------------------------------------

/// A 4096-aligned, interior-mutable 4 KiB cell that can live in an immutable
/// `static` (zero-initialised, so the linker places it in `.bss`, which the
/// boot trampoline clears before `rust_main`) while tb-hal mutates it through
/// raw pointers. Reuses the shared typed layout [`PageTable512`]
/// (`#[repr(C, align(4096))]` over `[u64; 512]`) for BOTH the new
/// paging-structure tables (TEST_PD / TEST_PT) and the two data frames
/// (FRAME_A / FRAME_B) — a test frame is just 4 KiB of `.bss` that gets
/// mapped and written.
#[repr(C)]
struct Cell4K(UnsafeCell<PageTable512>);

// SAFETY: M3 is single-vCPU with interrupts masked since boot, and every
// access to the interior goes through raw pointers from `UnsafeCell::get`
// (no `&`/`&mut` to the interior is ever materialised), so handing the cell
// out via a shared `static` cannot violate aliasing. `UnsafeCell` is what
// makes in-place mutation behind an immutable `static` defined behaviour.
unsafe impl Sync for Cell4K {}

impl Cell4K {
    /// A new zeroed cell; `const`, so it can initialise a `static` in `.bss`.
    const fn new() -> Self {
        Cell4K(UnsafeCell::new(PageTable512([0; 512])))
    }

    /// Raw pointer to the 8-byte entry `idx` of this cell (`idx < 512`).
    /// Pointer projection only — never materialises a reference.
    fn entry_ptr(&self, idx: usize) -> *mut u64 {
        debug_assert!(idx < 512);
        // SAFETY: `idx < 512` keeps the offset inside this one 4096-byte
        // allocation; `PageTable512` is `repr(C, align(4096))` over
        // `[u64; 512]`, so the element cast + offset is layout-exact.
        unsafe { (self.0.get() as *mut u64).add(idx) }
    }

    /// PHYSICAL base address of this cell, as stored into paging entries.
    /// The kernel image (and its `.bss`) is loaded at 1 MiB and the boot
    /// tables identity-map [0, 1 GiB), so virtual == physical here; the
    /// 4096-alignment guarantees the low 12 bits are clear, i.e. the value
    /// drops straight into the bits-51:12 address field.
    fn phys_base(&self) -> u64 {
        self.0.get() as u64
    }
}

/// The new page directory the self-test hangs off the boot PDPT's slot 1.
static TEST_PD: Cell4K = Cell4K::new();
/// The new page table behind `TEST_PD[0]`, holding the single test PTE.
static TEST_PT: Cell4K = Cell4K::new();
/// 4 KiB frame A — first mapping target of `TEST_VA`.
static FRAME_A: Cell4K = Cell4K::new();
/// 4 KiB frame B — remap target of `TEST_VA`.
static FRAME_B: Cell4K = Cell4K::new();

// ---------------------------------------------------------------------------
// Privileged register wrappers (A6/A9): ALL of the M3 x86_64 asm lives here.
// ---------------------------------------------------------------------------

/// Read CR3 — physical base of the live PML4 plus the PWT/PCD control bits.
///
/// (a) PRE: long mode, ring 0 (TABOS never leaves it). POST: returns the
///     live CR3 value; no architectural state changes.
/// (b) ABI: `mov {out}, cr3` — one GPR written; MOV-from-CR raises no flags;
///     nomem/nostack/preserves_flags.
/// (c) Tested by: scripts/run-x86_64.sh ("M3: mmu OK" — `mmu_selftest` walks
///     CR3 -> PML4[0] to locate the live boot PDPT).
#[inline]
unsafe fn read_cr3() -> u64 {
    let val: u64;
    // SAFETY: ring-0-only instruction; see (a). Callers are inside tb-hal.
    unsafe {
        asm!("mov {}, cr3", out(reg) val, options(nomem, nostack, preserves_flags));
    }
    val
}

/// Write CR3 — re-root the live paging hierarchy. Architectural side effect:
/// flushes all non-global TLB entries (SDM Vol 3A §4.10.4.1). Provided per
/// the M3 contract; UNUSED by the self-test, which splices into the LIVE
/// hierarchy precisely so that no CR3 reload is needed.
///
/// (a) PRE: ring 0; `val` = 4 KiB-aligned physical base of a valid PML4 for
///     the current paging mode (+ optional PWT/PCD bits). POST: CR3 = `val`;
///     non-global TLB entries flushed.
/// (b) ABI: `mov cr3, {in}`; no flags; NOT nomem — re-rooting translation
///     must order against surrounding memory accesses.
/// (c) Tested by: compiled into the M3 surface; first exercised when a real
///     address-space switch lands (post-M3).
#[inline]
#[allow(dead_code)]
unsafe fn write_cr3(val: u64) {
    // SAFETY: ring-0-only instruction; caller guarantees `val` is a valid
    // PML4 base — a bad root faults on the very next fetch or walk.
    unsafe {
        asm!("mov cr3, {}", in(reg) val, options(nostack, preserves_flags));
    }
}

/// `invlpg [va]` — invalidate any TLB entry for the page containing `va`
/// (and, per the SDM, associated paging-structure-cache entries).
///
/// (a) PRE: ring 0; paging on. POST: the next access to `va`'s page re-walks
///     the live tables instead of reusing a cached translation.
/// (b) ABI: `invlpg [{in}]` — address operand only, never dereferenced as
///     data; no flags; NOT nomem (memory accesses must not be reordered
///     across a TLB invalidation); nostack/preserves_flags.
/// (c) Tested by: scripts/run-x86_64.sh ("M3: mmu OK" — the remap is only
///     observable because `invlpg` evicts the stale FRAME_A translation).
#[inline]
unsafe fn invlpg(va: usize) {
    // SAFETY: ring-0-only instruction; see (a).
    unsafe {
        asm!("invlpg [{}]", in(reg) va, options(nostack, preserves_flags));
    }
}

/// Set/clear CR4.PGE (bit 7, Page Global Enable). Clearing then re-setting
/// PGE is the architectural "flush ALL TLB entries, global included" idiom
/// (SDM Vol 3A §4.10.4.1). Provided per the M3 contract; UNUSED by the
/// current self-test (the boot tables set no G bits, so `invlpg` suffices).
///
/// (a) PRE: ring 0. POST: CR4.PGE == `enable`, every other CR4 bit
///     preserved; a CR4 write that changes PGE flushes the TLB.
/// (b) ABI: `mov {out}, cr4` + `mov cr4, {in}` — read-modify-write through a
///     GPR; no flags; the WRITE is NOT nomem (TLB-flush side effect).
/// (c) Tested by: compiled into the M3 surface; exercised once global-page
///     mappings exist (none yet).
#[inline]
#[allow(dead_code)]
unsafe fn cr4_pge_toggle(enable: bool) {
    let mut cr4: u64;
    // SAFETY: ring-0-only instruction; pure read.
    unsafe {
        asm!("mov {}, cr4", out(reg) cr4, options(nomem, nostack, preserves_flags));
    }
    if enable {
        cr4 |= CR4_PGE;
    } else {
        cr4 &= !CR4_PGE;
    }
    // SAFETY: writes back the just-read value with only PGE changed, so CR4
    // stays self-consistent (PAE etc. untouched).
    unsafe {
        asm!("mov cr4, {}", in(reg) cr4, options(nostack, preserves_flags));
    }
}

/// `rdmsr` — read the 64-bit MSR selected by `msr` (EDX:EAX convention).
///
/// (a) PRE: ring 0; `msr` is implemented by the CPU (else #GP). POST:
///     returns EDX:EAX glued into one u64; no other state changes.
/// (b) ABI: ECX in, EAX/EDX out; flags unaffected; nomem/nostack/
///     preserves_flags (an MSR read has no memory side effect).
/// (c) Tested by: scripts/run-x86_64.sh ("M3: mmu OK" — `mmu_init`'s
///     read-modify-write of IA32_EFER).
#[inline]
unsafe fn rdmsr(msr: u32) -> u64 {
    let lo: u32;
    let hi: u32;
    // SAFETY: ring-0-only instruction; caller passes an implemented MSR.
    unsafe {
        asm!(
            "rdmsr",
            in("ecx") msr,
            out("eax") lo,
            out("edx") hi,
            options(nomem, nostack, preserves_flags),
        );
    }
    ((hi as u64) << 32) | (lo as u64)
}

/// `wrmsr` — write the 64-bit MSR selected by `msr` (EDX:EAX convention).
///
/// (a) PRE: ring 0; `msr` implemented and `val` legal for it (else #GP).
///     POST: the MSR holds `val`; for IA32_EFER.NXE this immediately turns
///     paging-entry bit 63 into the XD bit.
/// (b) ABI: ECX/EAX/EDX in; flags unaffected; NOT nomem (an MSR write can
///     change memory semantics — NXE alters how mappings behave);
///     nostack/preserves_flags.
/// (c) Tested by: scripts/run-x86_64.sh ("M3: mmu OK" — `mmu_init` sets
///     EFER.NXE and the kernel keeps executing + printing afterwards).
#[inline]
unsafe fn wrmsr(msr: u32, val: u64) {
    // SAFETY: ring-0-only instruction; caller guarantees msr/val legality.
    unsafe {
        asm!(
            "wrmsr",
            in("ecx") msr,
            in("eax") val as u32,
            in("edx") (val >> 32) as u32,
            options(nostack, preserves_flags),
        );
    }
}

// ---------------------------------------------------------------------------
// Safe M3 surface (re-exported through arch/mod.rs -> lib.rs).
// ---------------------------------------------------------------------------

/// x86_64 `mmu_init`: enable IA32_EFER.NXE so paging-entry bit 63 is the
/// architectural execute-disable (XD) bit (SDM Vol 3A §4.5 / Vol 4 Table 2-2
/// "IA32_EFER", bit 11 "Execute Disable Bit Enable").
///
/// Read-modify-write of one bit: idempotent, and preserves the LME/LMA/SCE
/// state the boot trampoline established. Every Firecracker-class x86_64
/// host (and QEMU TCG's default qemu64 model) implements NX
/// (CPUID.80000001H:EDX.NX = 1), so setting NXE cannot #GP on our targets.
/// IA32_PAT (MSR 0x277) is deliberately left at its power-up default — PAT
/// entry 0 is WB, which is what mappings with PWT=PCD=PAT=0 (all of ours)
/// select; per the M3 contract that is acceptable.
///
/// Call once from `rust_main`, AFTER `install_traps()` (a surprise #GP then
/// reports via the M1 trap path instead of triple-faulting).
pub fn mmu_init() {
    // SAFETY: ring 0 in long mode; IA32_EFER exists on every x86_64 CPU and
    // OR-ing NXE is legal whenever CPUID advertises NX (see above).
    unsafe {
        let efer = rdmsr(MSR_EFER);
        wrmsr(MSR_EFER, efer | EFER_NXE);
    }
}

/// x86_64 `mmu_selftest`: build, prove, REMAP and re-prove a 4 KiB mapping
/// for [`TEST_VA`] over the LIVE boot page tables. Returns `true` on pass.
/// Any structural surprise returns `false` (fail-closed — the kernel prints
/// "M3: FAIL"); a broken translation would #PF into the M1 trap path (whose
/// policy halts) and the runner's fail-closed timeout reports the missing
/// marker.
///
/// `TEST_VA = 0x4000_0000` decomposes (SDM Vol 3A §4.5, 4-level paging) as
/// PML4[0] -> PDPT[1] -> PD[0] -> PT[0]: PML4 slot 0 is the boot entry that
/// already points at `__boot_pdpt`, and PDPT slot 1 — the second gigabyte —
/// is VACANT because boot maps exactly [0, 1 GiB). Sequence:
///
///  1. Locate the boot PDPT: CR3 -> PML4[PML4_IDX] (the tables sit in
///     identity-mapped low RAM, so physical addresses deref directly).
///  2. Fail closed if PML4[0] is non-present or PDPT[1] is already present
///     (unexpected boot layout, or a second invocation).
///  3. Build BOTTOM-UP, publish LAST: TEST_PT[0] = FRAME_A|P|RW, TEST_PD[0]
///     = TEST_PT|P|RW, then PDPT[1] = TEST_PD|P|RW — the page walker can
///     never observe a half-built subtree. The `invlpg` here is
///     belt-and-suspenders only: a 0 -> 1 P transition needs no invalidation
///     (SDM Vol 3A §4.10.4.3).
///  4. MAP PROOF: write [`MAGIC_A`] through `TEST_VA`; read it back through
///     FRAME_A's identity address.
///  5. REMAP: seed FRAME_B with [`MAGIC_B`] via its identity address;
///     rewrite TEST_PT[0] = FRAME_B|P|RW; `invlpg TEST_VA` — REQUIRED now,
///     because step 4 cached the FRAME_A leaf in the TLB (SDM Vol 3A
///     §4.10.4.2). No break-before-make is needed on x86_64 (unlike
///     VMSAv8-64, the architecture has no TLB-conflict abort for a direct
///     valid -> valid rewrite on a single vCPU).
///  6. REMAP PROOF: read `TEST_VA`, expect [`MAGIC_B`].
pub fn mmu_selftest() -> bool {
    // SAFETY (whole test): ring 0, single vCPU, interrupts masked since
    // boot. Every table/frame byte is a tb-hal-owned static reached ONLY via
    // `UnsafeCell` raw pointers, so no Rust reference aliases memory the CPU
    // walker or the TEST_VA alias touches; all accesses through raw/mapped
    // addresses are volatile so the compiler can neither elide nor reorder
    // them around the table writes and `invlpg`.
    unsafe {
        // (1) CR3 -> live PML4 -> boot PDPT.
        let pml4 = (read_cr3() & PTE_ADDR_MASK) as *const u64;
        let pml4e = read_volatile(pml4.add(PML4_IDX));
        if pml4e & PTE_P == 0 {
            return false; // first GiB unmapped?! not the boot layout we built
        }
        let pdpt = (pml4e & PTE_ADDR_MASK) as *mut u64;
        let pdpte_slot = pdpt.add(PDPT_IDX);

        // (2) Target PDPT slot must be vacant (fail-closed re-run guard).
        if read_volatile(pdpte_slot) & PTE_P != 0 {
            return false;
        }

        // (3) Bottom-up build; top-level publish last; courtesy invlpg.
        write_volatile(
            TEST_PT.entry_ptr(PT_IDX),
            FRAME_A.phys_base() | PTE_P | PTE_RW,
        );
        write_volatile(
            TEST_PD.entry_ptr(PD_IDX),
            TEST_PT.phys_base() | PTE_P | PTE_RW,
        );
        write_volatile(pdpte_slot, TEST_PD.phys_base() | PTE_P | PTE_RW);
        invlpg(TEST_VA); // optional for 0->1 P (SDM 4.10.4.3); cheap insurance

        // (4) Map proof: in through the NEW VA, out through the identity VA.
        let test_va = TEST_VA as *mut u64;
        write_volatile(test_va, MAGIC_A);
        if read_volatile(FRAME_A.entry_ptr(0)) != MAGIC_A {
            return false;
        }

        // (5) Remap the leaf to FRAME_B; invlpg is REQUIRED here.
        write_volatile(FRAME_B.entry_ptr(0), MAGIC_B);
        write_volatile(
            TEST_PT.entry_ptr(PT_IDX),
            FRAME_B.phys_base() | PTE_P | PTE_RW,
        );
        invlpg(TEST_VA);

        // (6) Remap proof.
        read_volatile(test_va) == MAGIC_B
    }
}

//! x86_64 architecture backend for `tb-hal`.
//!
//! Exposes the safe primitives that `tb-hal`'s public API
//! (`serial_init`, `serial_write_byte`, `serial_write_str`, `halt`,
//! `install_traps`, `breakpoint`) delegates to via `arch::mod`. ALL x86_64
//! `unsafe` and assembly is confined to this `arch::x86_64` subtree
//! (KERNEL-FOUNDATION-SPEC §1); every other crate is `#![forbid(unsafe_code)]`.
//!
//! M0 boot path is PVH: `boot` emits the `XEN_ELFNOTE_PHYS32_ENTRY` note and
//! the (bootstrap-only) 32->64 trampoline; `serial` is the 16550 COM1 driver.
//! M1 adds CPU trap handling: `gdt` installs a permanent flat 64-bit GDT + TSS
//! (IST stacks), `idt` installs the 256-gate IDT, and `trap` holds the entry
//! thunks + the extern "C" handler that dispatches into safe Rust policy.
//! M2 adds the cooperative context switch: `sched` holds the naked
//! `ctx_switch` (saves/restores ONLY the psABI Fig. 3.4 callee-saved set
//! {rbx, rbp, r12-r15} + rsp, callee-saved-on-stack model) and the
//! initial-frame fabricator that tb-hal's shared `Task`/`task_create`/
//! `yield_to` layer builds on.
//! M3 adds the MMU layer: `mmu` holds the privileged paging-register
//! wrappers (read/write CR3, `invlpg`, CR4.PGE toggle, RDMSR/WRMSR for
//! IA32_EFER.NXE) plus the in-HAL `mmu_init`/`mmu_selftest` that splice a
//! new 4 KiB mapping at 0x4000_0000 into the LIVE boot page tables and
//! verify a remap with `invlpg`.

// `_start`, the PVH note and the 32->64 trampoline live here. The module is
// pulled into the final link because the linker script's `ENTRY(_start)`
// turns `_start` into a needed symbol, forcing extraction from the rlib.
pub mod boot;
pub mod serial;

// M1 trap stack: GDT/TSS, IDT, and the trap entry/dispatch asm + handler.
pub mod gdt;
pub mod idt;
pub mod trap;

// M2 cooperative switch: naked ctx_switch + new-task stack fabrication.
pub mod sched;

// M3 MMU: privileged paging-register wrappers (CR3, CR4.PGE, INVLPG,
// RDMSR/WRMSR for IA32_EFER.NXE) + the in-HAL 4 KiB map/remap self-test that
// splices a TEST_VA = 0x4000_0000 mapping into the live boot page tables.
pub mod mmu;

pub use serial::{serial_init, serial_write_byte};

// `breakpoint()` is re-exported as part of tb-hal's public trap surface; the
// `int3` lives in `trap.rs`. `set_trap_hook`/`TrapInfo`/`TrapKind`/`TrapAction`
// and the `dispatch_trap` glue live at the crate root (`lib.rs`).
pub use trap::breakpoint;

// M2: the arch-internal primitives consumed by the shared task layer in
// `lib.rs` (`Task`, `task_create`, `yield_to`). Per-arch contract:
//   * `unsafe extern "C" fn ctx_switch(prev_sp_save: *mut usize, next_sp: usize)`
//     — save the CURRENT task's callee-saved context on its own stack, store
//     the resulting SP to `*prev_sp_save`, adopt `next_sp` and resume the
//     next task (callee-saved-on-stack model, xv6 swtch.S shape).
//   * `fn task_stack_init(stack: &mut [usize], entry: fn()) -> usize`
//     — fabricate a brand-new task's initial frame on `stack` so the FIRST
//     switch into it `ret`s into `entry`; returns the initial saved-SP handle
//     that `task_create` records for the first `yield_to`.
// (Same names + signatures as the aarch64 arm, so `arch/mod.rs` re-exports
// one uniform contract to `lib.rs`.)
pub use sched::{ctx_switch, task_stack_init};

// M3: the safe MMU surface, re-exported through `arch/mod.rs` so `lib.rs` can
// expose `tb_hal::mmu_init` / `tb_hal::mmu_selftest`. `mmu_init` programs
// IA32_EFER.NXE once after `install_traps`; `mmu_selftest` builds, proves and
// remaps the 4 KiB test mapping entirely inside tb-hal, returning pass/fail.
// (Same names + signatures as the aarch64 arm, one uniform contract.)
pub use mmu::{mmu_init, mmu_selftest};

use core::sync::atomic::{AtomicBool, Ordering};

/// Guards `install_traps()` so the permanent GDT/TSS/IDT are only built once
/// per vCPU even if it is called more than once.
static TRAPS_INSTALLED: AtomicBool = AtomicBool::new(false);

/// Install real CPU exception/interrupt handling: load the permanent GDT+TSS
/// (with IST stacks) FIRST, then the IDT (whose #DF/NMI/#MC gates reference
/// those IST stacks). Idempotent; called once from `rust_main` via
/// `tb_hal::install_traps()`.
pub fn install_traps() {
    if TRAPS_INSTALLED.swap(true, Ordering::SeqCst) {
        return;
    }
    // Order matters: the IDT's IST indices select TSS stacks the GDT installs.
    gdt::init();
    idt::init();
}

/// Halt the calling (single) vCPU forever.
///
/// Masks interrupts and parks the core in a `hlt` loop. Used as the M0
/// Definition-of-Done terminator after the marker is printed, as the fatal
/// (`TrapAction::Halt`) trap terminator, and as the `#[panic_handler]`
/// fallback in the kernel crate. Never returns.
#[inline]
pub fn halt() -> ! {
    loop {
        // (a) PRE: any CPU state. POST: interrupts masked, core parked; the
        //     function never observably returns (the surrounding loop re-arms
        //     `hlt` after any spurious NMI/SMI wake).
        // (b) ABI: no operands; clobbers nothing; nomem/nostack. `hlt` clears
        //     no caller state; `cli` only affects IF.
        // (c) Tested by: scripts/run-x86_64.sh (kernel halts after emitting
        //     its markers; the runner times out and scrapes COM1).
        unsafe {
            core::arch::asm!("cli", "hlt", options(nomem, nostack, preserves_flags));
        }
    }
}

//! aarch64 MMU: cold bring-up (MAIR/TCR/TTBR0 -> SCTLR_EL1.M|C|I) plus the M3
//! 4 KiB map / Break-Before-Make remap self-test (units A6/A7/A9).
//!
//! Entered with the MMU OFF (QEMU `virt`, EL1h -- see `boot.rs`). [`mmu_init`]
//! brings translation up FROM COLD as a 39-bit-VA, 4 KiB-granule, 3-level
//! identity space:
//!
//!   * L1[0] = 1 GiB BLOCK @ PA 0x0000_0000, Device-nGnRnE (MAIR attr0) --
//!     covers the PL011 UART at 0x0900_0000 (`serial.rs`), so serial output
//!     surviving the enable proves this descriptor is right.
//!   * L1[1] = 1 GiB BLOCK @ PA 0x4000_0000, Normal WB RA/WA (MAIR attr1) --
//!     covers all of RAM (0x4000_0000..0x4800_0000, 128 MiB; image at
//!     0x4008_0000): our code, stack, and these very tables.
//!   * L1[2] (VA 0x8000_0000, 2 GiB) stays INVALID -- [`mmu_selftest`] hangs
//!     its L2 -> L3 -> 4 KiB test mapping there, outside the RAM gigabyte.
//!
//! VERIFIED facts this module is built on (sources re-fetched 2026-06-07; do
//! NOT change the constants without re-reading them):
//!
//!   * VMSAv8-64 descriptor low bits -- table = 0b11 (L0..L2), block = 0b01
//!     (L1/L2 leaf), page = 0b11 (L3 leaf); AttrIndx = bits[4:2]; AP[2:1] =
//!     bits[7:6] (0b00 = EL1 RW, no EL0); SH = bits[9:8] (0b11 = inner
//!     shareable); **AF = bit[10], MANDATORY on every leaf** (we install no
//!     Access-Flag-fault handler, so a cleared AF = synchronous abort on first
//!     access): Arm ARM DDI 0487, VMSAv8-64 translation table format
//!     descriptors (D8.3); cross-checked against Linux v6.6
//!     `arch/arm64/include/asm/pgtable-hwdef.h` -- `PMD_TYPE_SECT (1 << 0)`,
//!     `PUD_TYPE_TABLE (3 << 0)`, `PTE_TYPE_PAGE (3 << 0)`, `PTE_AF (1 << 10)`
//!     "Access Flag", `PTE_SHARED (3 << 8)` "SH[1:0], inner shareable",
//!     `PTE_ATTRINDX(t) ((t) << 2)`, `PTE_USER (1 << 6)` /* AP[1] */,
//!     `PTE_RDONLY (1 << 7)` /* AP[2] */ -- and the descriptor diagram in
//!     lowenware.com "AArch64 MMU Programming" (AF bit 10, SH 9:8, AP 7:6,
//!     INDX 4:2, TB bit 1, VB bit 0). (osdev.org "AArch64 Paging" documents
//!     the same layout; its CDN refused our fetch, hence the Linux + lowenware
//!     cross-check.)
//!   * TCR_EL1 fields -- T0SZ bits[5:0]; IRGN0 bits[9:8] / ORGN0 bits[11:10]
//!     (0b01 = WB RA/WA cacheable walks); SH0 bits[13:12] (0b11 = inner
//!     shareable); TG0 bits[15:14] (0b00 = 4 KiB); T1SZ bits[21:16]; EPD1
//!     bit[23] (1 = TTBR1_EL1 walks disabled); IPS bits[34:32] (0b010 =
//!     40-bit PA, the ID_AA64MMFR0_EL1.PARange encoding): Linux v6.6
//!     `pgtable-hwdef.h` -- `TCR_T0SZ_OFFSET 0`, `TCR_IRGN0_WBWA (1 << 8)`,
//!     `TCR_ORGN0_WBWA (1 << 10)`, `TCR_SH0_INNER (3 << 12)`,
//!     `TCR_TG0_4K (0 << 14)`, `TCR_T1SZ_OFFSET 16`, `TCR_EPD1_SHIFT 23`,
//!     `TCR_IPS_SHIFT 32`; Arm ARM TCR_EL1 (D19.2).
//!   * SCTLR_EL1 -- M = bit 0 (stage-1 MMU enable), C = bit 2 (data/unified
//!     caches), I = bit 12 (instruction caches): Linux v6.6 `sysreg.h` --
//!     `SCTLR_ELx_M (BIT(0))`, `SCTLR_ELx_C (BIT(2))`, `SCTLR_ELx_I
//!     (BIT(12))`; Arm ARM SCTLR_EL1 (D19.2).
//!   * MAIR_EL1 encodings -- Device-nGnRnE = 0x00, Normal WB RA/WA
//!     inner+outer = 0xFF, attribute n occupies bits [8n+7:8n]: Linux v6.6
//!     `sysreg.h` -- `MAIR_ATTR_DEVICE_nGnRnE UL(0x00)`, `MAIR_ATTR_NORMAL
//!     UL(0xff)`, `MAIR_ATTRIDX(attr, idx) ((attr) << ((idx) * 8))`; Arm ARM
//!     MAIR_EL1 (D19.2).
//!   * TLBI VA-operand -- operand bits[43:0] = VA[55:12], i.e. `VA >> 12`
//!     (ASID in bits[63:48]; zero here, and VAAE1IS matches All ASIDs anyway),
//!     and the canonical sequence `DSB ISHST -> TLBI -> DSB ISH -> ISB`:
//!     Linux v6.6 `tlbflush.h` -- `__TLBI_VADDR(addr, asid)` = `(addr) >> 12`
//!     masked to GENMASK(43,0), and `__flush_tlb_kernel_pgtable()` issues
//!     exactly `dsb(ishst); __tlbi(vaae1is, addr); dsb(ish); isb()`; VAAE1IS
//!     also drops walk-cache entries, which the remap relies on; Arm ARM TLB
//!     maintenance instructions (D8.14).
//!   * Break-Before-Make -- changing the output address of a live leaf
//!     requires: invalid descriptor -> barrier -> TLBI -> barrier -> new
//!     descriptor: Arm ARM DDI 0487, "Using break-before-make when updating
//!     translation table entries" (D8.16).
//!
//! All `unsafe` + `asm!` stays in tb-hal (framekernel rule); `lib.rs` exposes
//! the safe [`mmu_init`] / [`mmu_selftest`] surface to the
//! `#![forbid(unsafe_code)]` kernel crate. The typed 512-entry table layout
//! (`PageTable512`) is shared with the x86_64 backend via `crate::mmu`.

use core::cell::UnsafeCell;
use core::ptr::{read_volatile, write_volatile};

use crate::mmu::PageTable512;

// ===========================================================================
// Virtual layout
// ===========================================================================

/// The M3 test virtual address: 2 GiB. With T0SZ = 25 (39-bit VA, 3 levels)
/// the indices are L1 = VA[38:30] = 2, L2 = VA[29:21] = 0, L3 = VA[20:12] = 0.
/// L1[2] is the first gigabyte slot past the identity-mapped RAM gigabyte
/// (L1[1]), so this VA has NO translation until `mmu_selftest` installs one.
const TEST_VA: u64 = 0x8000_0000;

/// Identity gigabyte 0: MMIO, including the PL011 UART at 0x0900_0000.
const GIB0_DEVICE_PA: u64 = 0x0000_0000;
/// Identity gigabyte 1: RAM (QEMU `virt`, `-m 128M` => 0x4000_0000..0x4800_0000).
const GIB1_RAM_PA: u64 = 0x4000_0000;

// ===========================================================================
// VMSAv8-64 descriptor bits (verified -- module doc)
// ===========================================================================

/// Table descriptor (valid at L0..L2): bits[1:0] = 0b11; next-level table PA
/// lives in bits [47:12].
const DESC_TABLE: u64 = 0b11;
/// Block (leaf) descriptor at L1/L2: bits[1:0] = 0b01.
const DESC_BLOCK: u64 = 0b01;
/// Page (leaf) descriptor at L3: bits[1:0] = 0b11.
const DESC_PAGE: u64 = 0b11;
/// Access Flag, bit[10]. MUST be 1 on every leaf we write: tb-hal installs no
/// Access-Flag-fault handling, so a cleared AF means a fault/hang on the very
/// first access through the mapping.
const DESC_AF: u64 = 1 << 10;
/// SH[9:8] = 0b11, inner shareable. For Device memory the field is ignored
/// (Device is always treated as outer shareable), so the uniform value is
/// architecturally harmless on the Device block.
const DESC_SH_INNER: u64 = 0b11 << 8;
/// AttrIndx[4:2] = 0 -> MAIR_EL1 attr0 (Device-nGnRnE).
const DESC_ATTRIDX_DEVICE: u64 = 0 << 2;
/// AttrIndx[4:2] = 1 -> MAIR_EL1 attr1 (Normal WB RA/WA).
const DESC_ATTRIDX_NORMAL: u64 = 1 << 2;
// AP[7:6] = 0b00 (EL1 RW, no EL0 access) is the ABSENCE of bits 6 and 7.

/// 1 GiB Device leaf at L1: block | AF | SH | attr0 (= 0x701 over the PA).
const BLOCK_DEVICE: u64 = DESC_BLOCK | DESC_AF | DESC_SH_INNER | DESC_ATTRIDX_DEVICE;
/// 1 GiB Normal leaf at L1: block | AF | SH | attr1 (= 0x705 over the PA).
const BLOCK_NORMAL: u64 = DESC_BLOCK | DESC_AF | DESC_SH_INNER | DESC_ATTRIDX_NORMAL;
/// 4 KiB Normal leaf at L3: page | AF | SH | attr1 (= 0x707 over the PA).
const PAGE_NORMAL: u64 = DESC_PAGE | DESC_AF | DESC_SH_INNER | DESC_ATTRIDX_NORMAL;

// ===========================================================================
// MAIR_EL1 / TCR_EL1 / SCTLR_EL1 values (verified -- module doc)
// ===========================================================================

/// attr0 = 0x00 (Device-nGnRnE), attr1 = 0xFF (Normal WB RA/WA inner+outer).
const MAIR_VALUE: u64 = 0x00 | (0xFF << 8);

/// 39-bit VA (T0SZ = 25), 4 KiB granule, WB RA/WA cacheable inner-shareable
/// walks, 40-bit IPS, TTBR1 walks disabled. T1SZ is parked at 25 as well so
/// the (disabled) TTBR1 half still carries an architecturally valid size.
/// Computes to 0x2_0099_3519.
const TCR_VALUE: u64 = 25 // T0SZ, bits[5:0]: 64 - 25 = 39-bit VA, 3 levels @ 4 KiB
    | (0b01 << 8) // IRGN0 = WB RA/WA cacheable walks
    | (0b01 << 10) // ORGN0 = WB RA/WA cacheable walks
    | (0b11 << 12) // SH0   = inner shareable
    | (0b00 << 14) // TG0   = 4 KiB granule
    | (25 << 16) // T1SZ  (walks disabled by EPD1; keep the size field valid)
    | (1 << 23) // EPD1  = disable TTBR1_EL1 walks
    | (0b010 << 32); // IPS = 40-bit PA (ID_AA64MMFR0.PARange encoding 0b010)

/// SCTLR_EL1.M, bit 0: stage-1 MMU enable for EL1&0.
const SCTLR_M: u64 = 1 << 0;
/// SCTLR_EL1.C, bit 2: data / unified cache enable.
const SCTLR_C: u64 = 1 << 2;
/// SCTLR_EL1.I, bit 12: instruction cache enable.
const SCTLR_I: u64 = 1 << 12;

// ===========================================================================
// Static frames + tables (.bss -- zeroed by `_start`, boot.rs step (2), so
// every table starts all-invalid and both frames start all-zero)
// ===========================================================================

/// Interior-mutable, 4096-aligned page-table cell. `repr(transparent)` over
/// `UnsafeCell<PageTable512>` inherits the shared typed layer's
/// `#[repr(C, align(4096))]`, satisfying the walker's alignment rules
/// (TTBR0 BADDR and table pointers must be table-size aligned).
#[repr(transparent)]
struct TableCell(UnsafeCell<PageTable512>);

// SAFETY: single-vCPU target, cooperative kernel: there is no concurrent
// mutator. All interior access goes through this module's volatile helpers on
// raw pointers; no Rust reference to the interior is ever created or handed
// out, so the `Sync` impl cannot be used to alias `&mut`.
unsafe impl Sync for TableCell {}

impl TableCell {
    /// A new all-invalid (zeroed) table; `const`, so it can sit in `.bss`.
    const fn new() -> Self {
        TableCell(UnsafeCell::new(PageTable512([0; 512])))
    }

    /// Physical address of this table. Identity space: PA == VA both before
    /// the MMU is on (translation off) and after (RAM gigabyte is
    /// identity-mapped), so the pointer value IS the physical address.
    fn pa(&self) -> u64 {
        self.0.get() as u64
    }
}

/// A bare 4096-aligned, page-sized data frame for the self-test targets.
#[repr(C, align(4096))]
struct Frame4K(UnsafeCell<[u64; 512]>);

// SAFETY: as `TableCell` -- single vCPU, volatile raw-pointer access only,
// no interior references ever minted.
unsafe impl Sync for Frame4K {}

impl Frame4K {
    /// A new zeroed frame; `const`, so it can sit in `.bss`.
    const fn new() -> Self {
        Frame4K(UnsafeCell::new([0; 512]))
    }

    /// Physical address of this frame (identity space -- see `TableCell::pa`).
    fn pa(&self) -> u64 {
        self.0.get() as u64
    }
}

/// TTBR0_EL1 root: the L1 table (each entry covers 1 GiB under 39-bit VA).
static ID_L1: TableCell = TableCell::new();
/// Self-test L2 table hung under L1[2] (each entry covers 2 MiB).
static TEST_L2: TableCell = TableCell::new();
/// Self-test L3 table hung under TEST_L2[0] (each entry covers 4 KiB).
static TEST_L3: TableCell = TableCell::new();
/// Self-test frame A: first mapping target of TEST_VA.
static FRAME_A: Frame4K = Frame4K::new();
/// Self-test frame B: Break-Before-Make remap target of TEST_VA.
static FRAME_B: Frame4K = Frame4K::new();

/// Write one descriptor slot, volatile: the table walker reads these behind
/// the compiler's back, so ordinary stores could be reordered or elided.
fn table_set(table: &TableCell, idx: usize, desc: u64) {
    debug_assert!(idx < 512);
    // SAFETY: `table` is one of this module's static 4096-aligned tables;
    // `PageTable512` is `#[repr(C, align(4096))]` over `[u64; 512]` and
    // `TableCell` is `repr(transparent)`, so casting the cell pointer to
    // `*mut u64` and offsetting by `idx < 512` stays in bounds and aligned.
    // Single vCPU: no concurrent CPU-side access (the walker is hardware and
    // is sequenced by the explicit `dsb`s at the call sites).
    unsafe { write_volatile((table.0.get() as *mut u64).add(idx), desc) }
}

/// Volatile-write `value` into word 0 of `frame` THROUGH ITS IDENTITY ADDRESS
/// (the L1[1] Normal block) -- never through TEST_VA.
fn frame_write_ident(frame: &Frame4K, value: u64) {
    // SAFETY: word 0 of a static frame owned exclusively by this module,
    // accessed via its identity-mapped address: valid, aligned, single vCPU.
    unsafe { write_volatile(frame.0.get() as *mut u64, value) }
}

/// Volatile-read word 0 of `frame` through its identity address.
fn frame_read_ident(frame: &Frame4K) -> u64 {
    // SAFETY: as `frame_write_ident`; an aligned, side-effect-free load.
    unsafe { read_volatile(frame.0.get() as *const u64) }
}

// ===========================================================================
// Privileged system-register / barrier / TLBI wrappers (A6)
// ===========================================================================

// -- write_mair_el1() --------------------------------------------------------
// (a) PRE : EL1, any MMU state (called here with the MMU OFF). POST:
//           MAIR_EL1 = v; guaranteed visible to translation only after a
//           later `isb` (the caller's step (4)).
// (b) ABI : one `msr` from one input register; no memory, no stack, NZCV
//           preserved.
// (c) TEST: scripts/run-aarch64.sh -- serial alive after enable (attr0 right),
//           "M3: mmu OK" (attr1 right).
fn write_mair_el1(v: u64) {
    // SAFETY: writing MAIR_EL1 is legal at EL1 and only stages new
    // memory-attribute encodings; nothing observes them until the caller's
    // context-synchronizing `isb`.
    unsafe {
        core::arch::asm!(
            "msr mair_el1, {v}",
            v = in(reg) v,
            options(nomem, nostack, preserves_flags),
        );
    }
}

// -- write_tcr_el1() ---------------------------------------------------------
// (a) PRE : EL1, MMU OFF (changing TCR under a live MMU needs much more
//           ceremony than M3 performs). POST: TCR_EL1 = v; visible after the
//           caller's `isb`.
// (b) ABI : one `msr` from one input register; no memory, no stack, NZCV
//           preserved.
// (c) TEST: scripts/run-aarch64.sh -- any T0SZ/TG0/IPS mistake faults the
//           first translated fetch; the marker would never print.
fn write_tcr_el1(v: u64) {
    // SAFETY: writing TCR_EL1 is legal at EL1; with the MMU still off it
    // changes nothing until SCTLR_EL1.M is set after the caller's `isb`.
    unsafe {
        core::arch::asm!(
            "msr tcr_el1, {v}",
            v = in(reg) v,
            options(nomem, nostack, preserves_flags),
        );
    }
}

// -- write_ttbr0_el1() -------------------------------------------------------
// (a) PRE : EL1, MMU OFF; `v` = physical address of a 4096-aligned L1 table
//           whose entries are already published (`dsb ishst`). POST:
//           TTBR0_EL1 = v; the walker uses it after the caller's `isb` once
//           SCTLR_EL1.M is set.
// (b) ABI : one `msr` from one input register; no memory, no stack, NZCV
//           preserved.
// (c) TEST: scripts/run-aarch64.sh -- a wrong root would fault the first
//           translated access; marker absent.
fn write_ttbr0_el1(v: u64) {
    // SAFETY: writing TTBR0_EL1 is legal at EL1; `v` is the PA of our static,
    // correctly aligned `ID_L1` (BADDR alignment: 512 entries * 8 = 4096).
    unsafe {
        core::arch::asm!(
            "msr ttbr0_el1, {v}",
            v = in(reg) v,
            options(nomem, nostack, preserves_flags),
        );
    }
}

// -- sctlr_el1_set_bits() ----------------------------------------------------
// (a) PRE : tables + MAIR/TCR/TTBR0 programmed and `isb`-synchronized; MMU
//           OFF. POST: SCTLR_EL1 |= bits via read-modify-write (every other
//           bit preserved), pipeline flushed by the trailing `isb` -- with
//           bits = M|C|I the very next instruction executes under the new
//           identity translation with caches on.
// (b) ABI : mrs/orr/msr/isb; one scratch + one input register; no stack; NZCV
//           preserved (mrs/orr-register/msr set no flags). NOT `nomem`: this
//           is a whole-memory-context switch, so the compiler must not cache
//           memory state across it. (orr with #0x1005 is not a valid logical
//           immediate, hence the register-operand form.)
// (c) TEST: scripts/run-aarch64.sh -- "mmu-test: enabled, serial alive" prints
//           right after this returns.
fn sctlr_el1_set_bits(bits: u64) {
    // SAFETY: RMW of SCTLR_EL1 at EL1 with an immediate `isb`. The caller
    // (mmu_init) guarantees the identity tables cover the executing code,
    // stack, and UART before M|C|I flip on, so execution continues seamlessly
    // at the same (now-translated) addresses.
    unsafe {
        core::arch::asm!(
            "mrs {t}, sctlr_el1",
            "orr {t}, {t}, {b}",
            "msr sctlr_el1, {t}",
            "isb",
            t = out(reg) _,
            b = in(reg) bits,
            options(nostack, preserves_flags),
        );
    }
}

// -- dsb_ishst() -------------------------------------------------------------
// (a) PRE : any. POST: all PRIOR STORES are observable by every agent in the
//           inner shareable domain -- including the table walker -- before any
//           later memory op / TLBI executes.
// (b) ABI : one barrier instruction; no registers, no stack, NZCV preserved.
//           NOT `nomem`: it orders memory, so it must also be a compiler
//           barrier.
// (c) TEST: publishing descriptors before TTBR0 / before the L1 plug / before
//           TLBI in the BBM dance below; scripts/run-aarch64.sh marker.
fn dsb_ishst() {
    // SAFETY: barriers are side-effect-free synchronization, always legal.
    unsafe { core::arch::asm!("dsb ishst", options(nostack, preserves_flags)) }
}

// -- dsb_ish() -----------------------------------------------------------------
// (a) PRE : a TLBI (or stores) issued. POST: that TLBI and all prior memory
//           accesses in the inner shareable domain are COMPLETE -- the stale
//           translation is gone everywhere before anything later runs.
// (b) ABI : one barrier instruction; no registers, no stack, NZCV preserved.
//           NOT `nomem` (compiler barrier too).
// (c) TEST: the BBM remap below; scripts/run-aarch64.sh marker.
fn dsb_ish() {
    // SAFETY: as `dsb_ishst`.
    unsafe { core::arch::asm!("dsb ish", options(nostack, preserves_flags)) }
}

// -- isb() ---------------------------------------------------------------------
// (a) PRE : system-register writes / TLB maintenance pending architectural
//           visibility. POST: pipeline flushed; every later instruction
//           fetches and translates under the new context.
// (b) ABI : one barrier instruction; no registers, no stack, NZCV preserved.
//           NOT `nomem` (keeps ordering w.r.t. the surrounding sequence).
// (c) TEST: required after msr mair/tcr/ttbr0 and inside the BBM sequence;
//           scripts/run-aarch64.sh marker.
fn isb() {
    // SAFETY: as `dsb_ishst`.
    unsafe { core::arch::asm!("isb", options(nostack, preserves_flags)) }
}

// -- tlbi_vaae1is() ------------------------------------------------------------
// (a) PRE : the leaf for `va` was just invalidated and the store published
//           (`dsb ishst`). POST: once a following `dsb ish` completes, no TLB
//           or walk-cache entry for VA -- any ASID, EL1&0, inner shareable
//           domain -- survives.
// (b) ABI : `tlbi vaae1is, Xt` with Xt = VA >> 12 (operand bits [43:0] carry
//           VA[55:12]; ASID bits [63:48] zero -- VAAE1IS matches All ASIDs by
//           definition). Single vCPU: the -is (inner shareable) variant is
//           fine per spec; the local variant would be acceptable too.
// (c) TEST: after the BBM break, the read through TEST_VA observes frame B,
//           not a stale frame-A translation; scripts/run-aarch64.sh marker.
fn tlbi_vaae1is(va: u64) {
    let operand = va >> 12;
    // SAFETY: TLBI VAAE1IS is legal at EL1 and only discards cached
    // translations -- never memory contents. Operand format verified against
    // Linux `__TLBI_VADDR` (module doc).
    unsafe {
        core::arch::asm!(
            "tlbi vaae1is, {op}",
            op = in(reg) operand,
            options(nostack, preserves_flags),
        );
    }
}

// ===========================================================================
// M3 public surface (re-exported through arch/aarch64/mod.rs -> arch -> lib)
// ===========================================================================

// -- mmu_init() ----------------------------------------------------------------
// (a) PRE : EL1h, MMU OFF (cold, as `boot.rs` left it), `.bss` zeroed (so
//           ID_L1 starts all-invalid), install_traps() already called (a
//           bring-up mistake should vector into the M1 handler, not wedge
//           silently). POST: SCTLR_EL1.{M,C,I} = 1; identity translation live
//           (gigabyte 0 Device-nGnRnE, gigabyte 1 Normal WB); TTBR1 walks
//           disabled; L1[2] still invalid, reserved for mmu_selftest.
// (b) ABI : plain safe function; all asm confined to the leaf wrappers above.
// (c) TEST: kernel prints "mmu-test: enabled, serial alive" after this
//           returns -- the UART write through the Device block is the proof;
//           scripts/run-aarch64.sh.
/// Cold MMU bring-up: identity-map [0, 2 GiB) with two 1 GiB L1 blocks
/// (Device @ 0, Normal @ 0x4000_0000), program MAIR/TCR/TTBR0, `isb`, then
/// set SCTLR_EL1.M|C|I (read-modify-write) and `isb` again.
///
/// Call exactly once from `rust_main`, after `install_traps`. (A second call
/// would merely rewrite identical state, but it is not a supported pattern.)
pub fn mmu_init() {
    // (1) Build the identity L1 while the MMU is OFF (stores go straight to
    //     memory; cacheability cannot hide them from the walker yet).
    table_set(&ID_L1, 0, GIB0_DEVICE_PA | BLOCK_DEVICE);
    table_set(&ID_L1, 1, GIB1_RAM_PA | BLOCK_NORMAL);
    // (2) Publish the descriptors before the walker can be pointed at them.
    dsb_ishst();
    // (3) Program the translation regime: attributes, geometry, root.
    write_mair_el1(MAIR_VALUE);
    write_tcr_el1(TCR_VALUE);
    write_ttbr0_el1(ID_L1.pa());
    // (4) Context-synchronize the system-register writes...
    isb();
    // (5) ...then flip on MMU + D-cache + I-cache, preserving every other
    //     SCTLR_EL1 bit; the wrapper's trailing `isb` makes the next
    //     instruction run translated. Serial keeps working iff L1[0] is right.
    sctlr_el1_set_bits(SCTLR_M | SCTLR_C | SCTLR_I);
}

// -- mmu_selftest() --------------------------------------------------------------
// (a) PRE : mmu_init() returned (identity live, L1[2] invalid). Call ONCE:
//           the test leaves TEST_VA mapped to frame B and tears nothing down.
//           POST: true iff BOTH probes hit the right frame: (map TEST_VA ->
//           frame A, write via TEST_VA, verify via frame A's identity alias)
//           and (BBM remap to frame B, read via TEST_VA, verify frame B's
//           pre-seeded magic with frame A's value intact).
// (b) ABI : plain safe function; asm confined to the leaf wrappers.
// (c) TEST: kernel prints "M3: mmu OK" iff this returns true;
//           scripts/run-aarch64.sh greps exactly that marker, fail-closed.
/// M3 self-test: 4 KiB map at [`TEST_VA`] (1 GiB-hole VA 0x8000_0000), write
/// through the new mapping, verify through the identity alias, then remap to
/// a second frame with a full Break-Before-Make + `tlbi vaae1is` and verify
/// the VA now reads the second frame. `true` = pass.
pub fn mmu_selftest() -> bool {
    const MAGIC_A: u64 = 0xA11A_A11A_DEAD_BEEF;
    const MAGIC_B: u64 = 0xB22B_B22B_CAFE_F00D;

    // (0) Seed both frames through their IDENTITY addresses: frame B carries
    //     its magic BEFORE the test VA ever points at it; frame A starts 0.
    frame_write_ident(&FRAME_A, 0);
    frame_write_ident(&FRAME_B, MAGIC_B);

    // (1) First mapping: TEST_VA -> frame A. Build the chain bottom-up and
    //     plug it into the LIVE root last; the `dsb ishst` between the
    //     interior fill and the L1 plug keeps the walker from ever seeing a
    //     half-built chain. No TLBI needed for a first map: entries that
    //     fault (L1[2] was invalid) are architecturally never cached in a TLB.
    table_set(&TEST_L3, 0, FRAME_A.pa() | PAGE_NORMAL);
    table_set(&TEST_L2, 0, TEST_L3.pa() | DESC_TABLE);
    dsb_ishst();
    table_set(&ID_L1, 2, TEST_L2.pa() | DESC_TABLE);
    dsb_ishst();
    isb();

    // (2) Write the magic THROUGH the brand-new virtual mapping...
    // SAFETY: TEST_VA was just mapped read/write Normal onto FRAME_A, a
    // static frame this module owns exclusively; the access is an aligned
    // u64. Both aliases (TEST_VA and the identity address) carry identical
    // Normal WB inner-shareable attributes, so they are coherent views of
    // the same physical location.
    unsafe { write_volatile(TEST_VA as *mut u64, MAGIC_A) };
    // ...and verify it landed in frame A via the identity alias.
    if frame_read_ident(&FRAME_A) != MAGIC_A {
        return false;
    }

    // (3) Remap TEST_VA -> frame B: full Break-Before-Make (Arm ARM D8.16).
    //     BREAK: invalidate the leaf, publish, kill the cached translation,
    //     wait for the kill to complete, resync the pipeline...
    table_set(&TEST_L3, 0, 0);
    dsb_ishst();
    tlbi_vaae1is(TEST_VA);
    dsb_ish();
    isb();
    //     ...MAKE: install the new leaf and publish it.
    table_set(&TEST_L3, 0, FRAME_B.pa() | PAGE_NORMAL);
    dsb_ishst();
    isb();

    // (4) The same VA must now read frame B's pre-seeded magic...
    // SAFETY: TEST_VA is mapped onto FRAME_B (the BBM above completed); same
    // argument as step (2).
    let through_va = unsafe { read_volatile(TEST_VA as *const u64) };
    if through_va != MAGIC_B {
        return false;
    }
    // ...while frame A still holds its own value -- proving the remap moved
    // the translation rather than aliasing a single frame.
    frame_read_ident(&FRAME_A) == MAGIC_A
}

//! aarch64 backend for the `tb-hal` foundation crate.
//!
//! One of the two `#[cfg(target_arch)]` arms re-exported by `arch/mod.rs`. It
//! exposes the aarch64 primitives the safe `tb-hal` public API (`lib.rs`)
//! delegates to: [`serial_init`], [`serial_write_byte`], [`halt`] (M0), the
//! M1 trap surface [`install_traps`] and [`breakpoint`], the M2
//! cooperative-scheduling primitives [`ctx_switch`] and [`task_stack_init`]
//! (backing `lib.rs`'s safe `Task` / `task_create` / `yield_to`), and the M3
//! MMU surface [`mmu_init`] / [`mmu_selftest`] (cold stage-1 bring-up +
//! 4 KiB map / Break-Before-Make remap self-test).
//! (`serial_write_str` is composed in `lib.rs` from `serial_write_byte`, so it
//! is arch-independent.)
//!
//! Boot contract for the M0/M1 QEMU `virt` path (verified facts,
//! KERNEL-FOUNDATION-SPEC SS2): the vCPU enters `_start` at **EL1h, MMU OFF,
//! DAIF masked**, with **x0 = FDT/DTB pointer** (AAPCS64 arg0 already).
//! `boot.rs` owns that entry; `serial.rs` owns the PL011 UART; `vectors.rs`
//! owns the `VBAR_EL1` table; `trap.rs` owns the Rust trap dispatch;
//! `sched.rs` owns the M2 context switch (callee-saved x19..x30 + SP) and the
//! new-task initial-frame fabrication (x30 = entry); `mmu.rs` owns the M3
//! cold MMU bring-up (the MMU stays OFF until `rust_main` calls
//! [`mmu_init`] -- identity 1 GiB blocks: Device @ 0 covering the PL011,
//! Normal WB @ 0x4000_0000 covering RAM).

mod boot; // _start; arms VBAR_EL1; pure side-effect (`global_asm!`) module.
mod mmu; // M3: cold MMU bring-up + 4 KiB map / BBM remap self-test.
mod sched; // M2: ctx_switch (x19..x30 + SP) + initial-frame fabrication.
mod serial; // PL011 @ 0x0900_0000 (QEMU `virt` UART0).
mod trap; // Rust trap dispatch + breakpoint(); the only raw-frame deref.
mod vectors; // VBAR_EL1 table + entry/exit stubs; pure `global_asm!` module.

pub use mmu::{mmu_init, mmu_selftest};
pub use sched::{ctx_switch, task_stack_init};
pub use serial::{serial_init, serial_write_byte};
pub use trap::breakpoint;

// -- install_traps() --------------------------------------------------------
// (a) PRE : called once from rust_main, after serial_init, at EL1h. POST:
//           VBAR_EL1 == &__exception_vectors (the 2 KiB-aligned table in
//           vectors.rs) and an `isb` has made the new vector base
//           architecturally visible. Idempotent: `_start` already pre-armed the
//           very same table, so a second call just re-writes the same value.
// (b) ABI : clobbers one scratch x-register; touches no memory/stack; takes no
//           args. Arm ARM D19.2 requires a context-synchronisation event after
//           writing VBAR_EL1 before relying on it -- the `isb` provides it.
// (c) TEST: scripts/run-aarch64.sh -- after install, breakpoint() is caught,
//           the hook resumes, and the kernel prints "M1: traps OK".
/// Install the EL1 exception vectors (`VBAR_EL1`). Idempotent; call once.
pub fn install_traps() {
    // SAFETY: writing VBAR_EL1 is legal at EL1 and merely (re)selects our own
    // 2 KiB-aligned vector table (`vectors.rs`); `adrp/add :lo12:` form its
    // address with no memory access, and `isb` synchronises the change.
    unsafe {
        core::arch::asm!(
            "adrp {t}, __exception_vectors",
            "add  {t}, {t}, :lo12:__exception_vectors",
            "msr  vbar_el1, {t}",
            "isb",
            t = out(reg) _,
            options(nomem, nostack, preserves_flags),
        );
    }
}

// -- halt() -----------------------------------------------------------------
// (a) PRE : any state; called on the M0/M1 happy path after the marker is
//           flushed, from the kernel #[panic_handler], and from the trap
//           handler's fatal (Halt) path. POST: never returns -- the vCPU is
//           parked in a low-power wait, re-parking on any wake event.
// (b) ABI : `wfi` clobbers nothing, touches no memory/stack, preserves NZCV.
// (c) TEST: scripts/run-aarch64.sh -- the kernel reaches here after printing
//           "M1: traps OK"; the runner times out and asserts the marker.
/// Halt the current vCPU forever (low-power wait loop).
pub fn halt() -> ! {
    loop {
        // SAFETY: `wfi` is an unprivileged hint with no memory or stack
        // effects; it is always legal at EL1 and merely suspends the core
        // until a wake event, after which we loop and re-park.
        unsafe {
            core::arch::asm!("wfi", options(nomem, nostack, preserves_flags));
        }
    }
}

//! Shared typed page-table layer for M3 (`mmu_init` / `mmu_selftest`).
//!
//! Both TABOS architectures use the SAME radix-512 translation-table shape: a
//! table is 4 KiB = 512 × 8-byte entries and each level consumes a 9-bit
//! slice of the virtual address (Intel SDM Vol 3A §4.5 "4-Level Paging",
//! Table 4-15 entry formats; Arm ARM DDI 0487, VMSAv8-64 with the 4 KiB
//! granule). This module is that common shape, typed: a 4096-aligned
//! 512-entry table, a 4096-aligned data frame, and the pure entry/index
//! arithmetic — so the per-arch MMU backends (`arch/x86_64`, `arch/aarch64`)
//! share ONE audited implementation of the bit-slicing and keep their
//! `unsafe` confined to the actual register pokes, table installs and
//! mapped-VA derefs.
//!
//! NOTHING here touches hardware and nothing here is `unsafe`: pure data
//! layout + integer math. The single environmental assumption lives in
//! [`PageTable512::base_addr`] / [`Frame4K::base_addr`]: the kernel image is
//! identity-mapped (x86_64: the A0 boot tables identity-map [0, 1 GiB) with
//! 2 MiB pages; aarch64: tables are written while the MMU is OFF and the M3
//! tables identity-map the RAM gigabyte), so a static's virtual address IS
//! its physical address and may be planted into a parent entry / CR3 /
//! `TTBR0_EL1`.
//!
//! Verified bit facts the helpers rely on (sources re-checked for M3):
//!   * 512-entry tables, 9-bit index slices at shifts 39/30/21/12 — Intel SDM
//!     Vol 3A §4.5.4 (PML4/PDPT/PD/PT); Arm ARM VMSAv8-64 4 KiB granule
//!     (L1/L2/L3 under `T0SZ=25` = 39-bit VA, 3 levels).
//!   * Bit 0 is x86 `P`resent (SDM Table 4-15; Linux v6.6
//!     `arch/x86/include/asm/pgtable_types.h`: `_PAGE_BIT_PRESENT 0`) and
//!     VMSAv8 `Valid` (Linux v6.6 `arch/arm64/include/asm/pgtable-hwdef.h`:
//!     `PTE_VALID (1 << 0)`) on EVERY entry kind — so an all-zero table maps
//!     nothing on both architectures.
//!   * Output-address field: bits [47:12] are address bits on both arches for
//!     4 KiB-aligned tables/frames. x86_64 defines the field up to bit 51
//!     (MAXPHYADDR, SDM Table 4-15) but VMSAv8-64 puts upper ATTRIBUTES in
//!     [51:48] (e.g. DBM at bit 51), so [`ENTRY_ADDR_MASK`] keeps the
//!     portable [47:12] subset; every M3 table/frame sits far below 2^47
//!     (QEMU RAM < 4 GiB), so no address bit is ever masked away.

// Each arch backend consumes a SUBSET of this layer (e.g. aarch64's 3-level
// walk never uses SHIFT_512G; x86_64 never reads entries back); the unused
// remainder must not turn the other arch's build warning-noisy.
#![allow(dead_code)]

/// Bytes per page, per frame and per translation table (4 KiB granule, both
/// architectures).
pub const PAGE_SIZE: usize = 4096;

/// Entries per translation table: `4096 / 8 = 512` on both architectures.
pub const ENTRIES: usize = 512;

/// VA shift of the level whose entries each cover 512 GiB — x86_64 PML4.
/// (Unused by aarch64's 39-bit/3-level layout, which starts at 1 GiB.)
pub const SHIFT_512G: u32 = 39;

/// VA shift of the level whose entries each cover 1 GiB — x86_64 PDPT;
/// aarch64 L1 (the `TTBR0_EL1` root table under `T0SZ=25`).
pub const SHIFT_1G: u32 = 30;

/// VA shift of the level whose entries each cover 2 MiB — x86_64 PD
/// (`PS`-bit 2 MiB pages live here); aarch64 L2.
pub const SHIFT_2M: u32 = 21;

/// VA shift of the 4 KiB leaf level — x86_64 PT; aarch64 L3.
pub const SHIFT_4K: u32 = 12;

/// Output-address bits common to both architectures' 4 KiB-granule entries:
/// bits [47:12]. See the module docs for why [51:48] are deliberately NOT
/// included (x86 address bits up to MAXPHYADDR vs. VMSAv8 upper attributes).
pub const ENTRY_ADDR_MASK: u64 = 0x0000_FFFF_FFFF_F000;

/// The 9-bit table index a translation level consumes from `va`.
///
/// Both architectures slice the VA identically over 512-entry tables:
/// `index = (va >> shift) & 0x1FF` (Intel SDM Vol 3A §4.5.4; Arm ARM
/// VMSAv8-64 translation-walk, 4 KiB granule). Pass one of [`SHIFT_512G`],
/// [`SHIFT_1G`], [`SHIFT_2M`], [`SHIFT_4K`].
pub const fn level_index(va: u64, shift: u32) -> usize {
    ((va >> shift) & (ENTRIES as u64 - 1)) as usize
}

/// Compose a table entry / descriptor: 4 KiB-aligned output address plus the
/// caller's attribute bits.
///
/// `attrs` carries ALL low/high attribute bits — x86_64: `P`/`RW`/`PS`/`NX`…
/// (SDM Table 4-15); aarch64: valid/type, `AF`, `SH[1:0]`, `AP[2:1]`,
/// `AttrIndx[2:0]`… (Arm ARM VMSAv8-64 descriptor formats). This helper only
/// guarantees the address lands in the address field and nowhere else.
pub const fn make_entry(pa: u64, attrs: u64) -> u64 {
    (pa & ENTRY_ADDR_MASK) | attrs
}

/// The output address packed in an entry (the inverse of [`make_entry`]).
pub const fn entry_addr(entry: u64) -> u64 {
    entry & ENTRY_ADDR_MASK
}

/// Whether an entry is live: bit 0 is x86 `P`resent and VMSAv8 `Valid` on
/// both architectures (see the verified facts in the module docs).
pub const fn entry_is_valid(entry: u64) -> bool {
    entry & 1 != 0
}

/// One 4 KiB translation table: 512 × `u64` entries, 4096-aligned, so its
/// base address is directly plantable into a parent table entry, `CR3`, or
/// `TTBR0_EL1` (both architectures require table-granule alignment).
///
/// `const`-constructible all-zeroes, so per-arch `static` instances land in
/// `.bss` — and an all-zero table maps NOTHING on both architectures
/// (bit 0 = Present/Valid, see module docs), which is exactly the safe
/// starting state.
#[repr(C, align(4096))]
pub struct PageTable512(pub [u64; 512]);

impl PageTable512 {
    /// A new empty table (every entry not-present/invalid). `const` so it can
    /// initialise a `static` (placed in `.bss`, costing no image bytes).
    pub const fn new() -> Self {
        PageTable512([0; 512])
    }

    /// Read entry `idx`. Out-of-range panics — fail-closed through the kernel
    /// panic handler rather than a wild table poke.
    pub fn get(&self, idx: usize) -> u64 {
        self.0[idx]
    }

    /// Write entry `idx`. Out-of-range panics (fail-closed, as [`Self::get`]).
    ///
    /// NOTE: this is a plain store. Making it architecturally visible to the
    /// table walker — `dsb ishst` before enable/TLBI on aarch64 (Arm ARM
    /// VMSAv8-64 break-before-make), `invlpg` after changing a LIVE x86
    /// translation (SDM Vol 3A §4.10.4) — is the per-arch caller's job.
    pub fn set(&mut self, idx: usize, entry: u64) {
        self.0[idx] = entry;
    }

    /// This table's base address, for planting into a parent entry or a
    /// translation-base register. It is a PHYSICAL address only under the
    /// identity-mapping assumption spelled out in the module docs (true for
    /// the whole of M3 on both architectures).
    pub fn base_addr(&self) -> u64 {
        self as *const PageTable512 as usize as u64
    }
}

/// One 4 KiB data frame, 4096-aligned, viewed as 512 × `u64` words — the
/// mapping TARGET of the M3 self-test (frame A / frame B).
///
/// Zeroed at boot (`.bss`). The self-test writes magic words through the
/// freshly mapped test VA (a raw deref, confined to the per-arch backend) and
/// audits them through THIS identity-mapped view, which is plain safe field
/// access (`frame.0[i]`).
#[repr(C, align(4096))]
pub struct Frame4K(pub [u64; 512]);

impl Frame4K {
    /// A new zeroed frame. `const` so it can initialise a `static` (`.bss`).
    pub const fn new() -> Self {
        Frame4K([0; 512])
    }

    /// The frame's base address (physical under the identity-map assumption —
    /// module docs), for composing the 4 KiB leaf entry that maps it.
    pub fn base_addr(&self) -> u64 {
        self as *const Frame4K as usize as u64
    }
}

//! `tb-hal` — TABOS Hardware Abstraction Layer (M0 serial + M1 traps + M2
//! tasks + M3 MMU).
//!
//! This crate is the single place where `unsafe` and assembly are allowed in
//! TABOS (framekernel rule, KERNEL-FOUNDATION-SPEC.md §1). The raw pokes live in
//! the per-arch submodules under `arch/`; THIS file is a thin, mostly-safe
//! facade exposing the symbols the `kernel` crate is allowed to call:
//!
//! M0 serial + park:
//!   * [`serial_init`], [`serial_write_byte`], [`serial_write_str`], [`halt`]
//!
//! M1 traps:
//!   * [`install_traps`]  — load the permanent GDT+TSS+IDT (x86_64) / set
//!     `VBAR_EL1` (aarch64). Idempotent, called once from `rust_main`.
//!   * [`breakpoint`]     — execute a software breakpoint (`int3` / `brk #0`).
//!   * [`set_trap_hook`]  — register the safe dispatch policy hook.
//!   * [`TrapInfo`] / [`TrapKind`] / [`TrapAction`] — the safe trap-dispatch ABI.
//!
//! M2 cooperative tasks:
//!   * [`Task`], [`task_create`], [`yield_to`] — voluntary (cooperative)
//!     context switch between kernel tasks. Only the ABI callee-saved
//!     registers plus the stack pointer are switched; the saved SP is the
//!     ENTIRE per-task context handle (verified ABI facts in the M2 section
//!     below).
//!   * [`TaskStack`] — one-shot-takeable static stack cell, so the
//!     `#![forbid(unsafe_code)]` kernel crate can OWN its static stack arrays
//!     (tb-hal allocates nothing) and still mint the unique `&'static mut`
//!     that [`task_create`] requires.
//!   * [`current_task`] — handle of the task executing right now (slot 0 is
//!     the bootstrap context that entered `rust_main`).
//!
//! M3 MMU (this milestone):
//!   * [`mmu_init`]     — x86_64: program `EFER.NXE` over the already-live A0
//!     boot paging; aarch64: bring the MMU up FROM COLD — identity translation
//!     tables + `MAIR_EL1`/`TCR_EL1`/`TTBR0_EL1`, `isb`, then
//!     `SCTLR_EL1.{M,C,I}`, `isb`. Called once from `rust_main`, AFTER
//!     [`install_traps`].
//!   * [`mmu_selftest`] — the whole 4 KiB map → write → verify → remap →
//!     re-verify test lives INSIDE tb-hal (x86: PTE rewrite + `invlpg`;
//!     aarch64: full Break-Before-Make + `tlbi`); the kernel crate only sees
//!     the returned `bool`. The typed table layer both backends share is
//!     `mmu.rs` (`PageTable512` + entry/index math); raw derefs stay per-arch.
//!
//! POLICY lives in safe Rust: tb-hal's per-arch assembly marshals a raw
//! `TrapFrame`, an `extern "C"` handler in tb-hal (the ONLY place that derefs
//! the raw frame, `unsafe`) builds a safe [`TrapInfo`] and calls the registered
//! hook via [`dispatch_trap`]. The default hook returns [`TrapAction::Halt`].

#![no_std]
#![deny(missing_docs)]

use core::cell::UnsafeCell;
use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

mod arch;
mod mmu; // M3: shared typed page-table layer (PageTable512/Frame4K + entry math).

/// Initialise the early serial console for the current architecture.
///
/// * x86_64: legacy 16550 UART, COM1 @ I/O port `0x3F8`.
/// * aarch64: PL011 UART0 @ MMIO `0x0900_0000` (QEMU `virt` first-light).
///
/// Must be called once before any [`serial_write_byte`] / [`serial_write_str`].
pub fn serial_init() {
    arch::serial_init();
}

/// Write a single byte to the early serial console, blocking until the UART can
/// accept it.
pub fn serial_write_byte(b: u8) {
    arch::serial_write_byte(b);
}

/// Write a string to the early serial console, byte by byte (blocking).
///
/// Pure safe Rust: this is just a loop over [`serial_write_byte`]; it performs
/// no `unsafe` itself.
pub fn serial_write_str(s: &str) {
    for &b in s.as_bytes() {
        arch::serial_write_byte(b);
    }
}

/// Halt the (single) vCPU forever. Never returns.
///
/// * x86_64: masked `cli; hlt` spin.
/// * aarch64: `wfi` spin with interrupts masked.
pub fn halt() -> ! {
    arch::halt()
}

// ===========================================================================
// M1: trap installation + safe dispatch ABI
// ===========================================================================

/// Install real CPU exception/interrupt handling for the current architecture.
///
/// * x86_64: build and load a PERMANENT flat 64-bit GDT (null, ring0 code,
///   ring0 data, 64-bit TSS), reload `CS`/data segments, `ltr` the TSS, then
///   load a 256-entry IDT of 64-bit interrupt gates. `#DF`/NMI/`#MC` are routed
///   through TSS IST stacks.
/// * aarch64: point `VBAR_EL1` at the 2 KiB-aligned, 16×128-byte vector table.
///
/// Idempotent: safe to call more than once (each call rebuilds the descriptor
/// tables from scratch). Call once early from `rust_main`, before [`breakpoint`].
pub fn install_traps() {
    arch::install_traps();
}

/// Execute a software breakpoint trap on the current architecture.
///
/// * x86_64: `int3` (`#BP`, vector 3) — a TRAP whose CPU-saved `RIP` already
///   points PAST the instruction, so it resumes automatically on
///   [`TrapAction::Resume`].
/// * aarch64: `brk #0` — a SYNCHRONOUS exception (`ESR_EL1.EC = 0x3C`) whose
///   `ELR_EL1` points AT the instruction; the trap entry advances `ELR_EL1` by
///   4 on [`TrapAction::Resume`].
pub fn breakpoint() {
    arch::breakpoint();
}

/// The architecture-neutral classification of a trap, derived in the per-arch
/// `extern "C"` handler from the raw cause (vector + error code on x86_64,
/// `ESR_EL1.EC` on aarch64).
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum TrapKind {
    /// Software breakpoint: x86 `#BP` (vector 3) / aarch64 `brk` (EC `0x3C`).
    Breakpoint,
    /// Page / data fault: x86 `#PF` (vector 14) / aarch64 data abort
    /// (EC `0x24`/`0x25`). [`TrapInfo::fault_addr`] holds the faulting address.
    PageFault,
    /// Undefined / invalid instruction: x86 `#UD` (vector 6) / aarch64 Unknown
    /// (EC `0x00`).
    Undefined,
    /// Any other trap not specially classified above.
    Other,
}

/// What the dispatch hook asks tb-hal to do after a trap is handled.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum TrapAction {
    /// Return from the trap entry so execution continues past the trapping
    /// instruction (x86: `iretq`; aarch64: `eret`, advancing `ELR_EL1` by 4 for
    /// the at-instruction synchronous breakpoint).
    Resume,
    /// Do not return; park the vCPU forever. Used for fatal faults and as the
    /// default policy when no hook is registered.
    Halt,
}

/// A safe, fully-owned description of a trap, handed to the dispatch hook.
///
/// Built inside tb-hal's per-arch handler from the raw `TrapFrame`; it borrows
/// nothing from the raw frame, so the hook (in the otherwise-`forbid(unsafe)`
/// kernel crate) can read it freely.
#[derive(Clone, Copy, Debug)]
pub struct TrapInfo {
    /// The architecture-neutral kind of this trap.
    pub kind: TrapKind,
    /// Raw cause word. x86_64: `(vector << 32) | (error_code & 0xFFFF_FFFF)`.
    /// aarch64: the full `ESR_EL1` value (EC = bits `[31:26]`).
    pub cause: u64,
    /// Faulting address for memory faults (x86 `CR2` for `#PF`; aarch64
    /// `FAR_EL1` for a data abort), otherwise `0`.
    pub fault_addr: u64,
    /// The trapping instruction pointer (x86 saved `RIP`; aarch64 `ELR_EL1`).
    pub pc: u64,
}

/// Storage for the registered trap hook: a `fn(&TrapInfo) -> TrapAction`
/// reinterpreted as `usize`. `0` means "no hook registered → use the default
/// halt policy". `AtomicUsize` because tb-hal is `no_std` with no locks; the
/// pointer is written once at boot and read on every trap.
static TRAP_HOOK: AtomicUsize = AtomicUsize::new(0);

/// The default policy when no hook has been registered: always halt.
fn default_trap_hook(_info: &TrapInfo) -> TrapAction {
    TrapAction::Halt
}

/// Register the safe trap-dispatch policy hook.
///
/// The hook is a plain function pointer `fn(&TrapInfo) -> TrapAction`; it lives
/// in safe Rust (e.g. the kernel crate under `#![forbid(unsafe_code)]`) and
/// decides per-trap whether to [`TrapAction::Resume`] or [`TrapAction::Halt`].
pub fn set_trap_hook(hook: fn(&TrapInfo) -> TrapAction) {
    TRAP_HOOK.store(hook as usize, Ordering::Release);
}

/// Dispatch a trap to the registered hook (or the default halt policy).
///
/// Called by each per-arch `extern "C"` handler with a [`TrapInfo`] it built
/// from the raw frame. This is the safe boundary between the raw-frame deref
/// (per-arch, `unsafe`) and the policy hook (safe).
pub(crate) fn dispatch_trap(info: &TrapInfo) -> TrapAction {
    let raw = TRAP_HOOK.load(Ordering::Acquire);
    if raw == 0 {
        return default_trap_hook(info);
    }
    // SAFETY: `raw` is non-zero here, so it was produced by `set_trap_hook`
    // from a valid `fn(&TrapInfo) -> TrapAction` via `hook as usize`. A function
    // pointer and `usize` are both pointer-sized; this transmute is the exact
    // inverse of that cast.
    let hook: fn(&TrapInfo) -> TrapAction =
        unsafe { core::mem::transmute::<usize, fn(&TrapInfo) -> TrapAction>(raw) };
    hook(info)
}

// ===========================================================================
// M2: cooperative tasks + context switch
// ===========================================================================
//
// Saved-context model (callee-saved-on-stack, the classic cooperative switch):
// `yield_to` saves ONLY the callee-saved registers of the outgoing task onto
// the outgoing task's own stack and records the resulting stack pointer in
// that task's slot; resuming a task is "load its saved SP, pop the
// callee-saved set, return". A single `usize` (the saved SP) is therefore the
// whole per-task context. Caller-saved registers need no saving: `yield_to`
// is an ordinary function call, so the compiler already treats them as dead
// across it.
//
// Verified ABI facts (sources re-checked for M2 — do NOT change the register
// sets or frame layouts without re-reading them):
//  * x86-64 System V psABI (AMD64 ABI 1.0 draft, 2025-03-12, §3.2.1 + Fig 3.4
//    "Register Usage"): "Registers %rbp, %rbx and %r12 through %r15 'belong'
//    to the calling function and the called function is required to preserve
//    their values" → callee-saved GPRs = {rbx, rbp, r12, r13, r14, r15}
//    (+ rsp itself). §3.2.2 "The Stack Frame": at function entry "the value of
//    (%rsp + 8) is a multiple of 16", i.e. RSP % 16 == 8 right after `call`.
//  * AAPCS64 (ARM-software/abi-aa, aapcs64.rst, 2025Q4, §6.1.1 "General-purpose
//    registers"): "r19…r28 | Callee-saved registers" and "Registers r19-r29
//    and SP are Callee-saved"; r29 = FP, r30 = LR (the resume address rides in
//    LR; `ret` branches to it). §6.4.5.1 "Universal stack constraints":
//    "SP mod 16 = 0. The stack must be quad-word aligned."
//  * Initial-frame fabrication technique: OSDev wiki, "Brendan's Multi-tasking
//    Tutorial" (Step 1/2): "put values on the new kernel stack to match the
//    values that your switch_to_task(task) function expects to pop off the
//    stack after switching to the task" — i.e. a fake callee-saved frame whose
//    return address / LR is the task's entry, so the FIRST switch into the
//    task "returns" into `entry`.
//
// No FP/SIMD state is switched: both TABOS targets are soft-float target
// specs, so v8-v15 (AAPCS64) and the SSE/x87 state (psABI) cannot hold live
// values across the switch.

/// Number of task slots tb-hal tracks, INCLUDING slot 0, which is permanently
/// reserved for the bootstrap context (the stack `_start` set up and
/// `rust_main` runs on). M2 needs three (bootstrap + the two ping-pong tasks);
/// eight leaves headroom without needing a heap.
const MAX_TASKS: usize = 8;

/// Per-slot saved stack pointer — the WHOLE saved context of a suspended task
/// under the callee-saved-on-stack model. `0` means "no saved context" (slot
/// never created, or its task is currently running so its slot is stale).
/// `AtomicUsize` because tb-hal is `no_std` with no locks; M2 is single-core
/// cooperative, so the atomics are for safe interior mutability, not racing.
static TASK_SP: [AtomicUsize; MAX_TASKS] = [const { AtomicUsize::new(0) }; MAX_TASKS];

/// Slot index of the task currently executing on this (single) core.
/// `yield_to` updates it right before the raw switch, so a task that is
/// resumed always observes itself as current.
static CURRENT_TASK: AtomicUsize = AtomicUsize::new(0);

/// Next free slot in [`TASK_SP`]; slot 0 is the bootstrap context.
static NEXT_TASK_SLOT: AtomicUsize = AtomicUsize::new(1);

/// Smallest stack [`task_create`] accepts, in `usize` words. The fabricated
/// initial frame needs at most 13 words (aarch64: 12-register stp/ldp frame +
/// 16-byte re-alignment of the top); 64 words also gives the entry a little
/// room before it overflows. Real guard pages arrive with the MMU milestone.
const MIN_STACK_WORDS: usize = 64;

/// An opaque handle to a cooperative kernel task: the slot index into
/// tb-hal's internal saved-SP table. `Copy` so it can be passed around freely;
/// convertible to/from a raw `usize` (see [`Task::raw`]) so the
/// `forbid(unsafe_code)` kernel can stash handles in `AtomicUsize` statics.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct Task(usize);

impl Task {
    /// The raw slot index of this handle, for stashing in an `AtomicUsize`
    /// (cross-task handle passing in safe kernel code goes through statics).
    pub fn raw(self) -> usize {
        self.0
    }

    /// Rebuild a handle from a value previously obtained via [`Task::raw`].
    ///
    /// Safe: a fabricated/invalid index cannot cause memory unsafety — it is
    /// rejected fail-closed by [`yield_to`] (bounds check + "has this slot a
    /// saved context" check), which reports over serial and halts.
    pub fn from_raw(raw: usize) -> Self {
        Task(raw)
    }
}

/// Handle of the task currently executing (slot 0 — the bootstrap context —
/// until the first [`yield_to`] after [`task_create`]).
pub fn current_task() -> Task {
    Task(CURRENT_TASK.load(Ordering::Relaxed))
}

/// Fail-closed termination for misuse of the M2 task API: report the reason
/// over serial (best-effort) and park the core. Never returns.
fn task_api_fatal(msg: &str) -> ! {
    serial_write_str("tb-hal: task: ");
    serial_write_str(msg);
    serial_write_byte(b'\n');
    halt()
}

/// Create a cooperative task that will start executing `entry` the first time
/// somebody [`yield_to`]s it.
///
/// `stack` is caller-provided `'static` memory (the kernel owns its static
/// stack arrays — see [`TaskStack`]; tb-hal does NOT allocate). The arch
/// backend fabricates the INITIAL context frame at the 16-byte-aligned-down
/// top of `stack` — a fake callee-saved frame whose return address (x86_64) /
/// LR slot (aarch64) is `entry` and whose other slots are zero — so the first
/// switch into the task "returns" into `entry` with an ABI-conformant stack
/// (x86_64: RSP % 16 == 8 as after `call`, psABI §3.2.2; aarch64:
/// SP % 16 == 0, AAPCS64 §6.4.5.1).
///
/// `entry` must never return: there is no caller frame beneath it. End it in
/// `halt()` or park it by never yielding back. Fatal (reports + halts) if the
/// stack is too small or all task slots are used.
pub fn task_create(stack: &'static mut [usize], entry: fn()) -> Task {
    if stack.len() < MIN_STACK_WORDS {
        task_api_fatal("task_create: stack too small");
    }
    let slot = NEXT_TASK_SLOT.fetch_add(1, Ordering::Relaxed);
    if slot >= MAX_TASKS {
        task_api_fatal("task_create: too many tasks");
    }
    let sp = arch::task_stack_init(stack, entry);
    TASK_SP[slot].store(sp, Ordering::Release);
    Task(slot)
}

/// Cooperatively switch from the current context to `next`.
///
/// Saves the callee-saved registers + SP of the CURRENT task (on its own
/// stack), records the resulting SP in the current task's slot, then loads
/// `next`'s saved SP, restores its callee-saved registers and returns into it.
/// When somebody later yields back, this function simply returns to its
/// caller, all callee-saved state intact (psABI §3.2.1 / AAPCS64 §6.1.1).
///
/// M2 keeps scheduling explicit/manual: there is no run queue; the caller says
/// exactly which task runs next. Yielding to the current task is a no-op.
/// An invalid handle (out of range, or a slot with no saved context) is fatal:
/// reported over serial, then halt — never a wild jump.
pub fn yield_to(next: Task) {
    if next.0 >= MAX_TASKS {
        task_api_fatal("yield_to: invalid task handle");
    }
    let prev = CURRENT_TASK.load(Ordering::Relaxed);
    if prev == next.0 {
        return; // self-yield: nothing to switch
    }
    let next_sp = TASK_SP[next.0].load(Ordering::Acquire);
    if next_sp == 0 {
        task_api_fatal("yield_to: target has no saved context");
    }
    CURRENT_TASK.store(next.0, Ordering::Relaxed);
    // SAFETY: `next_sp` was produced either by `arch::task_stack_init` over a
    // caller-provided exclusive `&'static mut` stack (fabricated initial
    // frame) or by a previous `ctx_switch` save of a then-live task; both
    // leave a well-formed callee-saved frame at that SP. `TASK_SP[prev]
    // .as_ptr()` points into a `'static` atomic, valid for the single word
    // `ctx_switch` stores. Single core + cooperative switching: no other
    // context can touch either slot while the switch runs.
    unsafe { arch::ctx_switch(TASK_SP[prev].as_ptr(), next_sp) }
}

/// A statically-allocatable, 16-byte-aligned kernel task stack of `WORDS`
/// `usize` words, takeable exactly once as `&'static mut [usize]`.
///
/// Exists so the `#![forbid(unsafe_code)]` kernel crate can OWN its static
/// stack arrays (tb-hal allocates nothing) and still produce the unique
/// `&'static mut` that [`task_create`] requires — safe code cannot otherwise
/// mint a mutable reference into a `static`. The atomic one-shot gate makes
/// aliased handouts impossible; a second [`TaskStack::take`] is fatal
/// (reported over serial, then halt).
#[repr(C, align(16))]
pub struct TaskStack<const WORDS: usize> {
    // First field at offset 0 inherits the struct's 16-byte alignment — both
    // ABIs demand a 16-aligned stack (psABI §3.2.2; AAPCS64 §6.4.5.1
    // "SP mod 16 = 0"), and the arch frame builders keep it that way.
    mem: UnsafeCell<[usize; WORDS]>,
    // One-shot gate, flipped by the first `take()`.
    taken: AtomicBool,
}

// SAFETY: the ONLY route to the inner array is `take()`, whose atomic
// swap-once gate hands out at most one `&'static mut` ever (a racing second
// caller loses the swap and halts), so shared references to the cell are never
// used to alias the interior data.
unsafe impl<const WORDS: usize> Sync for TaskStack<WORDS> {}

impl<const WORDS: usize> TaskStack<WORDS> {
    /// A new zeroed stack; `const`, so it can initialise a kernel `static`.
    pub const fn new() -> Self {
        TaskStack {
            mem: UnsafeCell::new([0; WORDS]),
            taken: AtomicBool::new(false),
        }
    }

    /// Hand out the stack as `&'static mut [usize]` — exactly once.
    ///
    /// A second call on the same static is a fatal API misuse: it reports over
    /// serial and halts (fail-closed; it can never mint a second aliasing
    /// `&mut`).
    pub fn take(&'static self) -> &'static mut [usize] {
        if self.taken.swap(true, Ordering::AcqRel) {
            task_api_fatal("TaskStack::take: taken twice");
        }
        // SAFETY: the swap above guarantees this body runs at most once per
        // static instance, so the `&mut` minted here is unique for `'static`;
        // `UnsafeCell` makes mutating the interior of an immutable `static`
        // well-defined.
        let array: &'static mut [usize; WORDS] = unsafe { &mut *self.mem.get() };
        &mut array[..]
    }
}

// ===========================================================================
// M3: MMU bring-up + map/remap self-test
// ===========================================================================
//
// Division of labour (framekernel rule upheld): the typed table layer the two
// backends share is `mmu.rs` (`PageTable512`, `Frame4K`, entry/index math —
// pure safe Rust); ALL new `unsafe` + `asm!` (CR3/EFER/invlpg wrappers,
// MAIR/TCR/TTBR0/SCTLR writes, dsb/isb/tlbi, the mapped-VA derefs of the
// self-test) lives in `arch/x86_64/` and `arch/aarch64/`. The kernel crate
// only ever sees the two safe functions below.
//
// Verified facts (sources re-checked for M3 — do NOT change bit positions
// without re-reading them):
//  * Intel SDM Vol 3A §4.5 Table 4-15 paging-entry formats: P = bit 0,
//    R/W = bit 1, PS = bit 7 (2 MiB at PD level), XD/NX = bit 63 (honoured
//    only when EFER.NXE = 1). Cross-checked against Linux v6.6
//    arch/x86/include/asm/pgtable_types.h: `_PAGE_BIT_PRESENT 0`,
//    `_PAGE_BIT_RW 1`, `_PAGE_BIT_PSE 7`, `_PAGE_BIT_NX 63`.
//  * IA32_EFER = MSR 0xC000_0080, NXE = bit 11; IA32_PAT = MSR 0x277
//    (left at its power-on default for M3); CR4.PGE = bit 7 (Linux v6.6
//    msr-index.h: `MSR_EFER 0xc0000080`, `_EFER_NX 11`,
//    `MSR_IA32_CR_PAT 0x00000277`; processor-flags.h: `X86_CR4_PGE_BIT 7`).
//  * `invlpg m` (Intel SDM Vol 2 / felixcloutier): "Invalidates any TLB
//    entries specified with the source operand … flushes all TLB entries for
//    that page", privileged (CPL 0), "also invalidates any global TLB entries
//    for the specified page". Required after changing a LIVE PTE; adding a
//    brand-new (previously non-present) translation needs no flush
//    (SDM Vol 3A §4.10.4.3 delayed-invalidation allowance).
//  * SCTLR_EL1: M = bit 0, C = bit 2, I = bit 12 (Arm ARM DDI 0487; Linux
//    v6.6 sysreg.h `SCTLR_ELx_M BIT(0)`, `SCTLR_ELx_C BIT(2)`,
//    `SCTLR_ELx_I BIT(12)`). MAIR attr encodings: Device-nGnRnE = 0x00,
//    Normal WB RA/WA = 0xFF (sysreg.h `MAIR_ATTR_DEVICE_nGnRnE 0x00`,
//    `MAIR_ATTR_NORMAL 0xff`), one attribute byte per index
//    (`MAIR_ATTRIDX(attr, idx) = attr << (idx * 8)`).
//  * VMSAv8-64 descriptors (Arm ARM; Linux v6.6 pgtable-hwdef.h): block at
//    L1/L2 = 0b01 (`PMD_TYPE_SECT 1<<0`), table = 0b11 (`PMD_TYPE_TABLE
//    3<<0`), page at L3 = 0b11 (`PTE_TYPE_PAGE 3<<0`); AF = bit 10
//    (`PTE_AF 1<<10`) MUST be set on every leaf (no AF-fault handling);
//    SH[9:8] = 0b11 inner shareable (`PTE_SHARED 3<<8`); AP[7:6] = 0b00 =
//    EL1 RW (AP[1]=bit6 `PTE_USER`, AP[2]=bit7 `PTE_RDONLY` — both clear);
//    AttrIndx at bits [4:2] (`PTE_ATTRINDX(t) t<<2`).
//  * TLBI VA-operand format: VA >> 12 in bits [43:0] (ASID in [63:48], 0 for
//    vaaE1IS "all ASIDs" forms) — Linux v6.6 tlbflush.h `__TLBI_VADDR`:
//    `__ta = addr >> 12; __ta &= GENMASK_ULL(43, 0)`.

/// Bring the MMU for the current architecture to the M3 baseline. Call ONCE
/// from `rust_main`, AFTER [`install_traps`] — a broken mapping then reports
/// through the trap path (`TrapKind::PageFault`) instead of an opaque hang or
/// triple fault.
///
/// * x86_64: paging is already LIVE (the A0 boot trampoline built the
///   identity 2 MiB tables and loaded CR3 before `rust_main`); this programs
///   `EFER.NXE` (MSR `0xC000_0080`, bit 11) so PTE bit 63 (NX) is honoured
///   from M3 on. `IA32_PAT` (MSR `0x277`) keeps its power-on default.
/// * aarch64: the MMU is OFF until here. Builds the identity translation
///   tables while still off (L1[0] = Device-nGnRnE block covering the PL011
///   UART gigabyte, L1[1] = Normal-WB block covering RAM, AF set on every
///   leaf), then `dsb ishst` → `MAIR_EL1`/`TCR_EL1` (T0SZ=25, TG0=4K,
///   IRGN0/ORGN0=WBWA, SH0=inner, IPS=40-bit, EPD1=1) / `TTBR0_EL1` → `isb`
///   → set `SCTLR_EL1.{M,C,I}` preserving all other bits → `isb`. Serial
///   keeps working across the enable — that is the device-mapping proof the
///   kernel prints right after calling this.
pub fn mmu_init() {
    arch::mmu_init();
}

/// Run the in-HAL MMU map/remap self-test; `true` = pass.
///
/// The WHOLE test lives inside tb-hal: map `TEST_VA` (x86_64: `0x4000_0000`,
/// the 1 GiB line — OUTSIDE the boot identity map, PDPT index 1 is empty;
/// aarch64: `0x8000_0000`, the 2 GiB line — outside the RAM gigabyte, L1
/// index 2 is empty) to 4 KiB frame A, write a magic value through `TEST_VA`,
/// verify it through frame A's identity-mapped address; then remap `TEST_VA`
/// to frame B — x86: rewrite the PTE + `invlpg [TEST_VA]`; aarch64: full
/// Break-Before-Make (invalid descriptor → `dsb ishst` → `tlbi vaae1is,
/// VA>>12` → `dsb ish` → `isb` → new descriptor → `dsb ishst` → `isb`) — and
/// verify a read through `TEST_VA` now observes frame B's value.
///
/// Frames and tables are static, 4096-aligned, `.bss`-resident
/// (`mmu::Frame4K` / `mmu::PageTable512`); every raw pointer deref stays
/// inside tb-hal's arch backends. The `#![forbid(unsafe_code)]` kernel crate
/// only branches on the returned `bool`.
pub fn mmu_selftest() -> bool {
    arch::mmu_selftest()
}

//! TABOS kernel entry shim (M3: MMU bring-up + map/remap self-test).
//!
//! Framekernel rule: the kernel crate is otherwise safe Rust. THIS file is the
//! single permitted exception. It contains no `unsafe {}` blocks; the only
//! reason crate-level `forbid(unsafe_code)` is not applied here is that
//! `#[unsafe(no_mangle)]` is itself an *unsafe attribute* (it tells the linker
//! to expose `rust_main` un-mangled for tb-hal's `_start` to `call`/`b` into),
//! and the `unsafe_code` lint flags it. All real unsafe + assembly is confined
//! to tb-hal (KERNEL-FOUNDATION-SPEC.md §1).
//!
//! M2 (kept verbatim) proves the cooperative context switch: two kernel tasks
//! (A and B) on kernel-owned static stacks voluntarily `yield_to` each other
//! for `ROUND_TRIPS` strict A,B,A,B round-trips. tb-hal switches only the ABI
//! callee-saved registers + SP (x86-64 SysV psABI §3.2.1: {rbx, rbp,
//! r12..r15}; AAPCS64 §6.1.1: {x19..x28, x29, x30}), so each task carries
//! locals ACROSS every yield as a REGISTER-INTEGRITY CANARY: if the switch
//! corrupted a callee-saved register (or the saved SP), the loop counters,
//! accumulators or rotating patterns diverge and the test prints
//! "M2: FAIL <why>". On success it prints "M2: context-switch OK". The M0
//! serial hello and the M1 breakpoint round-trip are kept verbatim ahead of
//! it, so one boot proves every milestone.
//!
//! M3 (this milestone) appends the MMU proof. After printing the M2 verdict,
//! task A hands the CPU BACK to the bootstrap context — one more cooperative
//! switch over the very machinery M2 just proved — and `rust_main` continues:
//! `mmu_init()` (x86_64: program EFER.NXE over the already-live A0 boot
//! tables; aarch64: bring the MMU up from cold — identity tables, then
//! MAIR/TCR/TTBR0 → isb → SCTLR_EL1.{M,C,I} → isb), a serial line proving the
//! UART mapping survived the enable, then `mmu_selftest()`: tb-hal maps
//! TEST_VA (x86_64 0x4000_0000 / aarch64 0x8000_0000 — both OUTSIDE the
//! identity-mapped region) to 4 KiB frame A, writes magic through TEST_VA,
//! verifies via frame A's identity address, remaps TEST_VA to frame B (x86:
//! PTE rewrite + invlpg; aarch64: full Break-Before-Make + tlbi) and verifies
//! the read through TEST_VA now sees frame B. DoD marker: "M3: mmu OK".
//! ALL the new MMU unsafe/asm lives in tb-hal; this crate calls two safe
//! functions and branches on a bool.

#![no_std]
#![no_main]

use core::hint::black_box;
use core::panic::PanicInfo;
use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};
use tb_hal::{Task, TaskStack, TrapAction, TrapInfo, TrapKind};

/// Ping-pong round-trips (A→B→A counts as one). DoD asks for >= 1000.
const ROUND_TRIPS: usize = 1000;

/// `TURN` value meaning "task A must run this half-round".
const TURN_A: usize = 0;
/// `TURN` value meaning "task B must run this half-round".
const TURN_B: usize = 1;

/// Initial value of task A's rotating-pattern canary (arbitrary, asymmetric).
const PAT_A_INIT: usize = 0xA5A5_5A5A_DEAD_BEEF;
/// Initial value of task B's rotating-pattern canary (different from A's).
const PAT_B_INIT: usize = 0x0F0F_F0F0_CAFE_F00D;

// --- M2 scheduler bookkeeping (all in THIS forbid-class crate, all safe) ----
// Stacks are kernel-OWNED statics (tb-hal allocates nothing); `TaskStack` is
// tb-hal's one-shot cell that mints the `&'static mut [usize]` safe code
// cannot otherwise produce. 4096 words = 32 KiB per task.

/// Task A's stack: 4096 usize words (32 KiB), 16-byte aligned.
static STACK_A: TaskStack<4096> = TaskStack::new();
/// Task B's stack: 4096 usize words (32 KiB), 16-byte aligned.
static STACK_B: TaskStack<4096> = TaskStack::new();

/// Task A's handle as `Task::raw()`, stashed so task B can yield back to A.
static TASK_A_RAW: AtomicUsize = AtomicUsize::new(usize::MAX);
/// Task B's handle as `Task::raw()`, stashed so task A can yield to B.
static TASK_B_RAW: AtomicUsize = AtomicUsize::new(usize::MAX);

/// Bootstrap context's handle as `Task::raw()` (slot 0), stashed BEFORE the
/// ping-pong starts so task A can hand the CPU back to `rust_main` after the
/// M2 verdict — M3 then runs in the bootstrap context, after `install_traps`,
/// exactly as the milestone spec requires.
static BOOT_TASK_RAW: AtomicUsize = AtomicUsize::new(usize::MAX);

/// Set by task A immediately after it prints the M2 success marker and right
/// before it yields back to the bootstrap context. `rust_main` refuses to
/// start M3 without it (fail-closed against any stray resume of slot 0).
static M2_PASSED: AtomicBool = AtomicBool::new(false);

/// Whose half-round it is: the strict-alternation flag (TURN_A / TURN_B).
/// Each side asserts it on entry and flips it before yielding.
static TURN: AtomicUsize = AtomicUsize::new(TURN_A);

/// Shared increment counter: A sees it == 2*i at round i, B sees == 2*j + 1;
/// any double-run or skipped turn breaks the sequence immediately.
static COUNTER: AtomicUsize = AtomicUsize::new(0);

/// Set by task B after it audited its own canaries on its final round;
/// task A requires it before declaring the milestone passed.
static B_VERIFIED: AtomicBool = AtomicBool::new(false);

/// Boot entry. tb-hal's per-arch `_start` jumps here after it has set up a
/// stack, zeroed `.bss`, and placed the boot-info pointer in arg0 (SysV `rdi`
/// on x86_64 = `hvm_start_info` phys addr; AAPCS64 `x0` on aarch64 = FDT blob).
#[unsafe(no_mangle)]
pub extern "C" fn rust_main(boot_info: usize) -> ! {
    // M0..M3 ignore boot_info; a later milestone parses hvm_start_info / FDT.
    let _ = boot_info;

    // --- M0 proof (kept verbatim): serial first-light ----------------------
    tb_hal::serial_init();
    tb_hal::serial_write_str("hello from rust_main\n");

    // --- M1 proof (kept): install traps, take a breakpoint, resume ---------
    tb_hal::install_traps();
    tb_hal::set_trap_hook(trap_hook);
    tb_hal::serial_write_str("trap-test: triggering breakpoint\n");
    tb_hal::breakpoint(); // int3 (x86_64) / brk #0 (aarch64); hook -> Resume
    tb_hal::serial_write_str("trap-test: resumed past breakpoint\n");
    tb_hal::serial_write_str("M1: traps OK\n");

    // --- M2 proof (kept): cooperative context-switch ping-pong -------------
    // Create both tasks on kernel-owned static stacks, publish their handles
    // for cross-task use (handles travel as raw usizes through atomics — the
    // only `'static` channel available to forbid(unsafe_code) code), then hand
    // the CPU to task A. Task A returns the CPU here exactly once, after the
    // M2 verdict marker; any M2 failure halts inside fail() and never resumes
    // this context.
    tb_hal::serial_write_str("ctx-test: starting ping-pong\n");
    BOOT_TASK_RAW.store(tb_hal::current_task().raw(), Ordering::Release);
    let task_a = tb_hal::task_create(STACK_A.take(), task_a_main);
    let task_b = tb_hal::task_create(STACK_B.take(), task_b_main);
    TASK_A_RAW.store(task_a.raw(), Ordering::Release);
    TASK_B_RAW.store(task_b.raw(), Ordering::Release);
    tb_hal::yield_to(task_a);

    // Fail-closed gate: the ONLY legal way back here is task A's post-verdict
    // hand-off. Anything else (a stray yield to slot 0) is an M2 failure.
    if !M2_PASSED.load(Ordering::Acquire) {
        fail("bootstrap context resumed before the M2 verdict");
    }

    // --- M3: MMU bring-up + map/remap self-test ----------------------------
    // x86_64: EFER.NXE over the already-live A0 boot tables. aarch64: MMU
    // from cold (identity tables -> MAIR/TCR/TTBR0 -> isb -> SCTLR_EL1.M|C|I
    // -> isb). The "serial alive" line after mmu_init() is itself a proof:
    // on aarch64 it only prints if the Device mapping for the PL011 is right.
    tb_hal::serial_write_str("mmu-test: init\n");
    tb_hal::mmu_init();
    tb_hal::serial_write_str("mmu-test: enabled, serial alive\n");
    // The whole map -> write -> verify -> remap (x86: PTE + invlpg; aarch64:
    // Break-Before-Make + tlbi) -> re-verify test lives inside tb-hal; this
    // forbid(unsafe_code)-class crate only branches on the verdict.
    if tb_hal::mmu_selftest() {
        tb_hal::serial_write_str("M3: mmu OK\n"); // <-- the M3 DoD marker
    } else {
        tb_hal::serial_write_str("M3: FAIL\n");
    }
    tb_hal::halt()
}

/// Task A ("ping"): drives `ROUND_TRIPS` strict A,B,A,B round-trips against
/// task B, renders the M2 verdict, then hands the CPU back to the bootstrap
/// context so `rust_main` can run the M3 sequence.
///
/// REGISTER-INTEGRITY CANARY: `i`, `a_loops`, `a_sum` and `a_pat` stay live
/// ACROSS every `yield_to`. Caller-saved registers are dead at the call, so
/// the compiler holds these in callee-saved registers (or spills them to this
/// task's OWN stack — equally covered, since the switch must preserve the
/// saved SP). `black_box` keeps the optimizer from folding the checks away.
fn task_a_main() {
    let task_b = Task::from_raw(TASK_B_RAW.load(Ordering::Acquire));

    let mut a_loops: usize = 0; // canary 1: monotonic loop count
    let mut a_sum: usize = 0; // canary 2: accumulator over the index
    let mut a_pat: usize = PAT_A_INIT; // canary 3: rotating bit pattern

    let mut i: usize = 0;
    while i < ROUND_TRIPS {
        // Strict alternation: it must be A's turn, with the shared counter
        // exactly at 2*i (A and B each incremented it i times so far).
        if TURN.load(Ordering::Acquire) != TURN_A {
            fail("A: turn flag not A at round start");
        }
        let c = COUNTER.load(Ordering::Acquire);
        if c != 2 * i {
            fail("A: shared counter out of sequence");
        }
        // Canary: the local loop count must track the loop index exactly.
        if black_box(a_loops) != i {
            fail("A: local loop canary corrupted");
        }
        COUNTER.store(c + 1, Ordering::Release);
        a_loops = black_box(a_loops) + 1;
        a_sum = black_box(a_sum).wrapping_add(i);
        a_pat = black_box(a_pat).rotate_left(1);
        TURN.store(TURN_B, Ordering::Release);

        tb_hal::yield_to(task_b); // <-- the cooperative switch under test

        if TURN.load(Ordering::Acquire) != TURN_A {
            fail("A: alternation broken after resume");
        }
        i += 1;
    }

    // Final canary audit: recompute the expected values with the same ops in
    // a yield-free loop and compare against what survived 2*ROUND_TRIPS
    // context switches.
    let mut want_sum: usize = 0;
    let mut want_pat: usize = PAT_A_INIT;
    let mut k: usize = 0;
    while k < ROUND_TRIPS {
        want_sum = black_box(want_sum).wrapping_add(k);
        want_pat = black_box(want_pat).rotate_left(1);
        k += 1;
    }
    if black_box(a_loops) != ROUND_TRIPS {
        fail("A: final loop count wrong");
    }
    if black_box(a_sum) != want_sum {
        fail("A: final sum canary wrong");
    }
    if black_box(a_pat) != want_pat {
        fail("A: final pattern canary wrong");
    }
    if COUNTER.load(Ordering::Acquire) != 2 * ROUND_TRIPS {
        fail("A: final shared counter wrong");
    }
    if !B_VERIFIED.load(Ordering::Acquire) {
        fail("A: task B never reported success");
    }

    tb_hal::serial_write_str("M2: context-switch OK\n"); // <-- the M2 DoD marker

    // M3 hand-off: flag the verdict, then return the CPU to the bootstrap
    // context (slot 0) over the same cooperative-switch machinery this
    // milestone just proved. rust_main continues with the MMU sequence; this
    // task is never scheduled again.
    M2_PASSED.store(true, Ordering::Release);
    tb_hal::yield_to(Task::from_raw(BOOT_TASK_RAW.load(Ordering::Acquire)));

    // The bootstrap context ends the run in halt(); A must never resume.
    fail("A: resumed after handing control back to bootstrap")
}

/// Task B ("pong"): mirror half of the ping-pong, with its own canary locals
/// live across every yield. Audits its canaries on the FINAL round before the
/// last yield (A never resumes it afterwards) and publishes the verdict via
/// `B_VERIFIED`.
fn task_b_main() {
    let task_a = Task::from_raw(TASK_A_RAW.load(Ordering::Acquire));

    let mut b_loops: usize = 0; // canary 1: monotonic loop count
    let mut b_sum: usize = 0; // canary 2: accumulator over the index
    let mut b_pat: usize = PAT_B_INIT; // canary 3: rotating bit pattern

    let mut j: usize = 0;
    while j < ROUND_TRIPS {
        if TURN.load(Ordering::Acquire) != TURN_B {
            fail("B: turn flag not B at round start");
        }
        let c = COUNTER.load(Ordering::Acquire);
        if c != 2 * j + 1 {
            fail("B: shared counter out of sequence");
        }
        if black_box(b_loops) != j {
            fail("B: local loop canary corrupted");
        }
        COUNTER.store(c + 1, Ordering::Release);
        b_loops = black_box(b_loops) + 1;
        b_sum = black_box(b_sum).wrapping_add(j);
        b_pat = black_box(b_pat).rotate_left(1);
        j += 1;

        if j == ROUND_TRIPS {
            // Last round: audit B's canaries NOW — after the yield below this
            // task is parked forever, so this is its only chance to report.
            let mut want_sum: usize = 0;
            let mut want_pat: usize = PAT_B_INIT;
            let mut k: usize = 0;
            while k < ROUND_TRIPS {
                want_sum = black_box(want_sum).wrapping_add(k);
                want_pat = black_box(want_pat).rotate_left(1);
                k += 1;
            }
            if black_box(b_loops) != ROUND_TRIPS {
                fail("B: final loop count wrong");
            }
            if black_box(b_sum) != want_sum {
                fail("B: final sum canary wrong");
            }
            if black_box(b_pat) != want_pat {
                fail("B: final pattern canary wrong");
            }
            B_VERIFIED.store(true, Ordering::Release);
        }

        TURN.store(TURN_A, Ordering::Release);
        tb_hal::yield_to(task_a); // <-- the cooperative switch under test
    }

    // Only reachable if A (wrongly) resumes B after its last round.
    fail("B: resumed after completing all rounds")
}

/// Emit the M2 failure verdict ("M2: FAIL <why>") over serial and park the
/// core. Never returns; the run scripts then miss the M3 marker (which is
/// only ever reached THROUGH a passing M2) and fail.
fn fail(why: &str) -> ! {
    tb_hal::serial_write_str("M2: FAIL ");
    tb_hal::serial_write_str(why);
    tb_hal::serial_write_byte(b'\n');
    tb_hal::halt()
}

/// Safe trap-dispatch policy hook (kept from M1: policy lives in this
/// `forbid(unsafe_code)`-class crate, not in tb-hal's raw entry asm).
///
/// tb-hal's per-arch `extern "C"` handler builds this [`TrapInfo`] from the raw
/// `TrapFrame` and calls us. A [`TrapKind::Breakpoint`] is resumed (prove the
/// round-trip); any other trap is reported and the core is halted — including
/// any [`TrapKind::PageFault`] a broken M3 mapping would raise.
fn trap_hook(info: &TrapInfo) -> TrapAction {
    match info.kind {
        TrapKind::Breakpoint => {
            tb_hal::serial_write_str("trap: breakpoint, resuming\n");
            TrapAction::Resume
        }
        _ => {
            // Fatal fault: report the cause/faulting-address/pc, then halt.
            tb_hal::serial_write_str("trap: fatal fault, halting\n");
            tb_hal::serial_write_str("  cause=");
            write_hex_u64(info.cause);
            tb_hal::serial_write_str(" fault_addr=");
            write_hex_u64(info.fault_addr);
            tb_hal::serial_write_str(" pc=");
            write_hex_u64(info.pc);
            tb_hal::serial_write_byte(b'\n');
            TrapAction::Halt
        }
    }
}

/// Write a `u64` as a fixed-width 16-digit `0x…` hex string over serial.
///
/// Pure safe Rust (no `core::fmt`, no allocation): just shifts nibbles out of
/// the value and emits ASCII via the tb-hal byte writer.
fn write_hex_u64(value: u64) {
    tb_hal::serial_write_str("0x");
    let mut shift: i32 = 60;
    while shift >= 0 {
        let nibble = ((value >> shift) & 0xf) as u8;
        let c = if nibble < 10 {
            b'0' + nibble
        } else {
            b'a' + (nibble - 10)
        };
        tb_hal::serial_write_byte(c);
        shift -= 4;
    }
}

/// Panic handler: best-effort marker over serial, then halt forever.
#[panic_handler]
fn panic(_info: &PanicInfo) -> ! {
    tb_hal::serial_write_str("panic\n");
    tb_hal::halt()
}
